public Program(){Runtime.UpdateFrequency=UpdateFrequency.Update1;_booting=true;_bootPhase=0;DrawBoot(0f,"Initialising...");}
public void Save(){Storage="SAFE="+(_safeMode?"1\n":"0\n")+"SORTERS="+(_sortersOn?"1\n":"0\n");}
public void Main(string arg,UpdateType src){if(Runtime.UpdateFrequency!=UpdateFrequency.Update1)Runtime.UpdateFrequency=UpdateFrequency.Update1;if((src&(UpdateType.Terminal|UpdateType.Trigger|UpdateType.Script))!=0){DoCmd(arg);return;}if(_booting){Boot();return;}try{_fastTick++;AutoLcdWatch();if(_booting){Boot();return;}bool live=_fastTick%10==0,heavy=_fastTick%10==5;if(live)FastLiveDashboards();if(!heavy){_lastMs=Runtime.LastRunTimeMs;_lastInstr=Runtime.CurrentInstructionCount;Echo("AUTOGRID MANAGER v3.0 LIVE "+_step+"/"+TOTAL_STEPS+" "+_stepName+"\nErr:"+_errCnt+" Ms:"+_lastMs.ToString("F1"));return;}_stepName=(_step<STEP_NAMES.Length)?STEP_NAMES[_step]:"Step "+_step;if(_step==0)S0_Scan();else if(_step==1)S1_FindItems();else if(_step==2)P2Control();else if(_step==3)S3_Assign();else if(_step==4)S4_Stock();else if(_step==5)S5_Sort();else if(_step==6)S6_Balance();else if(_step==7)S7_Turrets();else if(_step==8)S8_Ice();else if(_step==9)S9_Uranium();else if(_step==10)S10_Amounts();else if(_step==11)S12_AsmClean();else if(_step==12)S15_OreBalance();else if(_step==13)S16_RefSort();else if(_step==14)S17_InternalSort();else if(_step==15)CDrawPB();else if(_step==16)CDrawMain();else if(_step==17)DrawAlert();else if(_step==18)DrawPower();else if(_step==19)DrawFuel();else if(_step==20)DrawDock();else if(_step==21)DrawDef();else if(_step==22)DrawProd();else if(_step==23)DrawLog();else if(_step==24)DrawInventoryStep();_step++;if(_step>=TOTAL_STEPS)_step=0;_lastMs=Runtime.LastRunTimeMs;_lastInstr=Runtime.CurrentInstructionCount;}catch(Exception ex){_errCnt++;_lastErr=ex.Message;Log("ERR "+_step+": "+ex.Message);Echo("ERR step "+_step+": "+ex.Message);_step++;if(_step>=TOTAL_STEPS)_step=0;}Echo("AUTOGRID MANAGER v3.0 "+_step+"/"+TOTAL_STEPS+" "+_stepName+"\nErr:"+_errCnt+" Ms:"+_lastMs.ToString("F1"));}
void Boot(){if(_bootPhase==0){string gcd=Me.CustomData;int gi=gcd.IndexOf("group=");_grpTag=gi>=0?gcd.Substring(gi+6).Split('\n')[0].Trim():"";LoadState();EnsureQuotaTemplate();EnsureConfig();LoadDisplayQuotas();LoadConfig();ResetLcds();BindLcds();DrawBootAll(.05f,"Initialising LCDs...");_bootPhase++;return;}if(_bootPhase==1){DrawBootAll(.18f,"Preparing surfaces...");_bootPhase++;return;}if(_bootPhase==2){S0_Scan();DrawBootAll(.38f,"Scanning blocks...");_bootPhase++;return;}if(_bootPhase==3){S1_FindItems();DrawBootAll(.58f,"Reading inventories...");_bootPhase++;return;}if(_bootPhase==4){P2Scan();DrawBootAll(.74f,"Loading systems...");_bootPhase++;return;}if(_bootPhase==5){ResetLcds();BindLcds();DrawBootAll(.90f,"Binding LCD roles...");_bootPhase++;return;}DrawBootAll(1f,"Ready");_lcdSig=LcdSignature();_lcdRescanTimer=0;_lcdWatch=0;_bootPhase=0;_booting=false;_step=0;}
void LoadState(){if(string.IsNullOrEmpty(Storage))return;foreach(var line in Storage.Split('\n')){if(line.StartsWith("SAFE="))_safeMode=line.EndsWith("1");else if(line.StartsWith("SORTERS="))_sortersOn=line.EndsWith("1");}}
void EnsureQuotaTemplate(){if(Me.CustomData.Contains(QUOTA_START))return;var sb=new StringBuilder();sb.Append("\n");sb.Append(QUOTA_START);sb.Append("\n~ LCD bars show current amount / quota. Use Type/Subtype when names are ambiguous.\n");foreach(var n in ORE_NAMES)sb.Append("Ore/"+n+"=100000\n");foreach(var n in INGOT_NAMES)sb.Append("Ingot/"+n+"=100000\n");foreach(var n in COMP_NAMES)sb.Append("Component/"+n+"=10000\n");foreach(var n in AMMO_NAMES)sb.Append("AmmoMagazine/"+n+"=100\n");foreach(var n in FOOD_SUBS)sb.Append("ConsumableItem/"+n+"=100\n");foreach(var n in MEAL_NAMES)sb.Append("ConsumableItem/"+n+"=100\n");foreach(var n in ING_SUBS)sb.Append("ConsumableItem/"+n+"=500\n");foreach(var n in PHYS_ING)sb.Append("PhysicalObject/"+n+"=500\n");sb.Append("GasContainerObject/HydrogenBottle=20\nOxygenContainerObject/OxygenBottle=20\nSeedItem/Fruit=100\nSeedItem/Grain=100\nSeedItem/Mushrooms=100\nSeedItem/Vegetables=100\n");sb.Append(QUOTA_END);sb.Append("\n");Me.CustomData+=sb.ToString();}
void LoadDisplayQuotas(){_displayQuota.Clear();string cd=Me.CustomData;int s=cd.IndexOf(QUOTA_START),e=cd.IndexOf(QUOTA_END);if(s<0)return;int nl=cd.IndexOf('\n',s);int bs=nl>=0?nl+1:s,be=e>=0?e:cd.Length;if(bs>=be)return;foreach(var line in cd.Substring(bs,be-bs).Split('\n')){string ln=line.Trim();if(string.IsNullOrEmpty(ln)||ln.StartsWith("~")||ln.StartsWith("@"))continue;int eq=ln.IndexOf('=');if(eq<1)continue;string key=ln.Substring(0,eq).Trim();double q;if(!double.TryParse(ln.Substring(eq+1).Trim(),out q)||q<0)continue;_displayQuota[key]=q;if(key.Contains("/")){MyDefinitionId id=default(MyDefinitionId);if(MyDefinitionId.TryParse(OB+key,out id))_known.Add(id);}}}
void EnsureConfig(){if(Me.CustomData.Contains(CFG_START))return;if(Me.CustomData.Contains(OLD_CFG_START)){Me.CustomData=Me.CustomData.Replace(OLD_CFG_START,CFG_START).Replace(OLD_CFG_END,CFG_END);return;}Me.CustomData+="\n"+CFG_START+"\nBatteryEngineOn=25\nBatteryEngineOff=100\nH2Warn=30\nH2Crit=10\nO2Warn=30\nO2Crit=10\nIceWarn=10000\nIceCrit=1000\nCargoWarn=85\nCargoCrit=98\nUraniumWarn=10\nLargeReactorUranium=200\nSmallReactorUranium=50\nSmallGridReactorUranium=25\n"+CFG_END+"\n";}
double ConfigVal(string k,double d){string cd=Me.CustomData;int s=cd.IndexOf(CFG_START),e=cd.IndexOf(CFG_END);if(s<0)return d;int p=cd.IndexOf(k+"=",s,StringComparison.OrdinalIgnoreCase);if(p<0||e>0&&p>e)return d;int n=cd.IndexOf('\n',p);double v;return double.TryParse(cd.Substring(p+k.Length+1,(n<0?cd.Length:n)-p-k.Length-1).Trim(),out v)?v:d;}
void LoadConfig(){pBatOn=ConfigVal("BatteryEngineOn",25);pBatOff=ConfigVal("BatteryEngineOff",100);pH2Warn=ConfigVal("H2Warn",30);pH2Crit=ConfigVal("H2Crit",10);pO2Warn=ConfigVal("O2Warn",30);pO2Crit=ConfigVal("O2Crit",10);pIceWarn=ConfigVal("IceWarn",10000);pIceCrit=ConfigVal("IceCrit",1000);pCargoWarn=ConfigVal("CargoWarn",85);pCargoCrit=ConfigVal("CargoCrit",98);pUWarn=ConfigVal("UraniumWarn",10);pULarge=ConfigVal("LargeReactorUranium",200);pUSmall=ConfigVal("SmallReactorUranium",50);pUSmallGrid=ConfigVal("SmallGridReactorUranium",25);}
void DoCmd(string arg){if(string.IsNullOrEmpty(arg))return;string c=arg.Trim().ToLower();if(c=="reset"||c=="reboot"){_booting=true;_bootPhase=0;_step=0;_errCnt=0;Log("Reboot.");}else if(c=="safemode"){_safeMode=true;SetSafe();Save();Log("Safe mode ON");}else if(c=="combatmode"){_safeMode=false;SetSafe();Save();Log("Combat mode ON");}else if(c=="sorterson"){_sortersOn=true;SetSorters();Save();Log("AGM inventory sorter ON");}else if(c=="sortersoff"){_sortersOn=false;SetSorters();Save();Log("AGM inventory sorter OFF");}else if(c=="sort"){_step=5;}else if(c=="asmstatus"){Log("Assemblers: "+_asm.Count);foreach(var a in _asm)Log((a.IsProducing?"WORKING ":"IDLE ")+a.CustomName);}else if(c=="quotas"){EnsureQuotaTemplate();LoadDisplayQuotas();Log("Display quotas loaded: "+_displayQuota.Count);}}
void S0_Scan(){_all.Clear();_src.Clear();_oreC.Clear();_ingC.Clear();_cmpC.Clear();_ammoC.Clear();_toolC.Clear();_botC.Clear();_foodC.Clear();_seedC.Clear();_ingIC.Clear();_stkC.Clear();_typedC.Clear();_untagged.Clear();_asm.Clear();_ref.Clear();_arc.Clear();_react.Clear();_tanks.Clear();_gens.Clear();_bats.Clear();_guns.Clear();_excl.Clear();var connScr=new List<IMyShipConnector>();GridTerminalSystem.GetBlocksOfType<IMyShipConnector>(connScr,c=>HasTag(c,NO_AGM)&&c.Status==MyShipConnectorStatus.Connected);_exclConn.Clear();foreach(var c in connScr){var o=c.OtherConnector;if(o==null)continue;bool otherIsLocal=o.CubeGrid.IsSameConstructAs(Me.CubeGrid);var exConn=otherIsLocal?c:o;if(exConn.CubeGrid!=Me.CubeGrid){_excl.Add(exConn.CubeGrid);_exclConn.Add(exConn);}}_blkScr.Clear();GridTerminalSystem.GetBlocksOfType<IMyTerminalBlock>(_blkScr,b=>b.HasInventory&&b.IsFunctional);foreach(var b in _blkScr)Classify(b);SortPri(_oreC);SortPri(_ingC);SortPri(_cmpC);SortPri(_ammoC);SortPri(_toolC);SortPri(_botC);SortPri(_foodC);SortPri(_seedC);SortPri(_ingIC);_untagged.Sort((a,b)=>((float)b.GetInventory(0).MaxVolume).CompareTo((float)a.GetInventory(0).MaxVolume));P2Scan();}
void Classify(IMyTerminalBlock b){if(IsExcluded(b))return;string n=b.CustomName;bool noSort=HasTag(b,NO_SORT),locked=HasTag(b,LOCKED),hidden=HasTag(b,HIDDEN)||!b.ShowInInventory,stock=HasTag(b,STOCK_TAG);if(!hidden)_all.Add(b);var asm=b as IMyAssembler;if(asm!=null){if(!HasTag(b,NO_AGM)&&!HasTag(b,MANUAL)){bool sameGrid=b.CubeGrid.IsSameConstructAs(Me.CubeGrid);bool grpMatch=_grpTag.Length>0&&n.Contains(GRP_PFX+_grpTag+"]");bool role=HasTag(b,ASM_TAG)||HasTag(b,BASIC_ASM_TAG);if(sameGrid||grpMatch||role)_asm.Add(asm);}return;}var ref_=b as IMyRefinery;if(ref_!=null){bool sameGridR=b.CubeGrid.IsSameConstructAs(Me.CubeGrid);bool grpMatchR=_grpTag.Length>0&&n.Contains(GRP_PFX+_grpTag+"]");if(sameGridR||grpMatchR){if(b.BlockDefinition.SubtypeId.Contains("ArcFurnace")||b.BlockDefinition.SubtypeId.Contains("Blast"))_arc.Add(ref_);else _ref.Add(ref_);}return;}if(b is IMyReactor){if(b.CubeGrid.IsSameConstructAs(Me.CubeGrid))_react.Add(b as IMyReactor);return;}if(b is IMyGasTank){if(b.CubeGrid.IsSameConstructAs(Me.CubeGrid))_tanks.Add(b as IMyGasTank);return;}if(b is IMyGasGenerator){if(b.CubeGrid.IsSameConstructAs(Me.CubeGrid))_gens.Add(b as IMyGasGenerator);return;}if(b is IMyBatteryBlock){if(b.CubeGrid.IsSameConstructAs(Me.CubeGrid))_bats.Add(b as IMyBatteryBlock);return;}if(b is IMyUserControllableGun){if(b.CubeGrid.IsSameConstructAs(Me.CubeGrid)&&!HasTag(b,NO_AGM)&&!HasTag(b,MANUAL))_guns.Add(b as IMyUserControllableGun);return;}if(noSort||locked)return;if(stock){_stkC.Add(b);return;}bool isMachine=(b is IMyProductionBlock)||(b is IMyShipWelder)||(b is IMyShipGrinder)||(b is IMyShipDrill)||(b is IMyUserControllableGun);bool noPull=HasTag(b,NO_PULL);if(!hidden&&!isMachine&&!noPull)_src.Add(b);bool typed=false;if(HasTag(b,KW_ORE)){_oreC.Add(b);typed=true;}if(HasTag(b,KW_INGOT)){_ingC.Add(b);typed=true;}if(HasTag(b,KW_COMP)){_cmpC.Add(b);typed=true;}if(HasTag(b,KW_AMMO)){_ammoC.Add(b);typed=true;}if(HasTag(b,KW_TOOLS)){_toolC.Add(b);typed=true;}if(HasTag(b,KW_BOTTLES)){_botC.Add(b);typed=true;}if(HasTag(b,KW_FOOD)){_foodC.Add(b);typed=true;}if(HasTag(b,KW_SEEDS)){_seedC.Add(b);typed=true;}if(HasTag(b,KW_ING)){_ingIC.Add(b);typed=true;}if(typed)_typedC.Add(b);else if(b is IMyCargoContainer&&b.CubeGrid.IsSameConstructAs(Me.CubeGrid))_untagged.Add(b);}
void P2Scan(){_pReact.Clear();_pTank.Clear();_pGen.Clear();_pH2Eng.Clear();_pBat.Clear();_pVent.Clear();_pDock.Clear();_pTurret.Clear();_pAsm.Clear();_pRef.Clear();_pAlertLight.Clear();_pSolar.Clear();_pWind.Clear();_pSorter.Clear();var l=new List<IMyTerminalBlock>();GridTerminalSystem.GetBlocksOfType<IMyTerminalBlock>(l,b=>b.CubeGrid.IsSameConstructAs(Me.CubeGrid)&&!IsExcluded(b));foreach(var b in l){var r=b as IMyReactor;if(r!=null&&HasTag(b,P_REACT))_pReact.Add(r);var t=b as IMyGasTank;if(t!=null&&HasTag(b,P_TANK))_pTank.Add(t);var g=b as IMyGasGenerator;if(g!=null&&HasTag(b,P_GEN))_pGen.Add(g);var bat=b as IMyBatteryBlock;if(bat!=null&&HasTag(b,P_BAT))_pBat.Add(bat);var v=b as IMyAirVent;if(v!=null&&HasTag(b,P_VENT))_pVent.Add(v);var d=b as IMyShipConnector;if(d!=null&&HasTag(b,P_DOCK))_pDock.Add(d);var gun=b as IMyUserControllableGun;if(gun!=null&&HasTag(b,P_TURRET))_pTurret.Add(gun);var a=b as IMyAssembler;if(a!=null&&(HasTag(b,ASM_TAG)||HasTag(b,BASIC_ASM_TAG)))_pAsm.Add(a);var rf=b as IMyRefinery;if(rf!=null&&HasTag(b,P_REF))_pRef.Add(rf);var li=b as IMyLightingBlock;if(li!=null&&HasTag(b,P_ALERT))_pAlertLight.Add(li);var pp=b as IMyPowerProducer;if(pp!=null&&HasTag(b,P_SOLAR))_pSolar.Add(pp);else if(pp!=null&&HasTag(b,P_WIND))_pWind.Add(pp);var so=b as IMyConveyorSorter;if(so!=null)_pSorter.Add(so);var fb=b as IMyFunctionalBlock;if(fb!=null&&HasTag(b,P_H2ENG))_pH2Eng.Add(fb);}SetSafe();SetSorters();P2Metrics();}
void P2Metrics(){double cur=0,max=0;foreach(var b in _pBat){cur+=b.CurrentStoredPower;max+=b.MaxStoredPower;}_batPct=max>0?cur/max*100:0;double h=0,o=0;int hc=0,oc=0;foreach(var t in _pTank){if(t.BlockDefinition.SubtypeId.IndexOf("Hydrogen",StringComparison.OrdinalIgnoreCase)>=0){h+=t.FilledRatio;hc++;}else{o+=t.FilledRatio;oc++;}}_h2Pct=hc>0?h/hc*100:0;_o2Pct=oc>0?o/oc*100:0;_uranium=0;var u=MyItemType.MakeIngot("Uranium");foreach(var r in _pReact)_uranium+=(double)r.GetInventory(0).GetItemAmount(u);_ice=0;var ice=MyItemType.MakeOre("Ice");foreach(var g in _pGen)_ice+=(double)g.GetInventory(0).GetItemAmount(ice);double cv=0,cm=0;foreach(var b in _all)for(int i=0;i<b.InventoryCount;i++){cv+=(double)b.GetInventory(i).CurrentVolume;cm+=(double)b.GetInventory(i).MaxVolume;}_cargoPct=cm>0?cv/cm*100:0;P2Alert();}
void P2Control(){LoadConfig();P2Metrics();bool h2=_pReact.Count>0&&_pBat.Count>0&&_uranium<=0&&_batPct<pBatOn;if(_uranium>0||_batPct>=pBatOff)h2=false;foreach(var e in _pH2Eng)e.Enabled=h2;foreach(var g in _pGen)g.AutoRefill=true;RefillBottles();BalanceTanks();SetSafe();SetSorters();}
void BalanceTanks(){double h=0,o=0;int hc=0,oc=0;foreach(var t in _pTank){bool hy=t.BlockDefinition.SubtypeId.IndexOf("Hydrogen",StringComparison.OrdinalIgnoreCase)>=0;if(hy){h+=t.FilledRatio;hc++;}else{o+=t.FilledRatio;oc++;}}foreach(var t in _pTank){bool hy=t.BlockDefinition.SubtypeId.IndexOf("Hydrogen",StringComparison.OrdinalIgnoreCase)>=0;double av=hy?(hc>0?h/hc:0):(oc>0?o/oc:0);t.Stockpile=t.FilledRatio<av-.02;}}
void SetSafe(){foreach(var t in _pTurret)t.Enabled=!_safeMode;}
void SetSorters(){foreach(var s in _pSorter)s.Enabled=_sortersOn;}
void RefillBottles(){RefillBottlesOf("");}
void RefillBottlesOf(string tid){if(_pGen.Count==0)return;var sources=new List<IMyTerminalBlock>();sources.AddRange(_botC);sources.AddRange(_src);foreach(var g in _pGen){var d=g.GetInventory(0);if(!InvNotFull(d))continue;foreach(var b in sources){if(b==g||!b.HasInventory)continue;var s=b.GetInventory(0);foreach(var n in BOTTLE_NAMES){string bt=n=="OxygenBottle"?T_OXY:T_GAS;if(tid.Length>0&&bt!=tid)continue;MyItemType it=MyItemType.Parse(OB+bt+"/"+n);double a=(double)s.GetItemAmount(it);if(a>0)XferType(it.ToString(),s,d,a);}}}}
void P2Alert(){_alertLevel=0;var a=new List<string>();if(_pBat.Count>0&&_batPct<pBatOn){_alertLevel=1;a.Add("POWER LOW");}if(_pReact.Count>0){if(_uranium<=0){_alertLevel=Math.Max(_alertLevel,1);a.Add("URANIUM DEPLETED");}else if(_uranium<pUWarn){_alertLevel=Math.Max(_alertLevel,1);a.Add("URANIUM LOW");}}bool ht=false,ot=false;foreach(var t in _pTank)if(t.BlockDefinition.SubtypeId.IndexOf("Hydrogen",StringComparison.OrdinalIgnoreCase)>=0)ht=true;else ot=true;if(ht){if(_h2Pct<pH2Crit){_alertLevel=2;a.Add("HYDROGEN CRITICAL");}else if(_h2Pct<pH2Warn){_alertLevel=Math.Max(_alertLevel,1);a.Add("HYDROGEN LOW");}}if(ot){if(_o2Pct<pO2Crit){_alertLevel=2;a.Add("OXYGEN CRITICAL");}else if(_o2Pct<pO2Warn){_alertLevel=Math.Max(_alertLevel,1);a.Add("OXYGEN LOW");}}if(_pGen.Count>0){if(_ice<pIceCrit){_alertLevel=2;a.Add("ICE CRITICAL");}else if(_ice<pIceWarn){_alertLevel=Math.Max(_alertLevel,1);a.Add("ICE LOW");}}if(_cargoPct>=pCargoCrit){_alertLevel=2;a.Add("CARGO FULL");}else if(_cargoPct>=pCargoWarn){_alertLevel=Math.Max(_alertLevel,1);a.Add("CARGO HIGH");}foreach(var t in _pTurret)if(!t.IsFunctional){_alertLevel=Math.Max(_alertLevel,1);a.Add("TURRET OFFLINE");break;}foreach(var x in _pAsm)if(!x.IsQueueEmpty&&!x.IsProducing){_alertLevel=Math.Max(_alertLevel,1);a.Add("ASSEMBLER STUCK");break;}_alertText=a.Count==0?"ALL SYSTEMS OK":string.Join(" | ",a);foreach(var l in _pAlertLight){string role=AlertRoleName(l);string title="",stat="",detail="";double pct=0;Color c;float blink;AlertData(role,out title,out stat,out detail,out pct,out c,out blink);l.Enabled=true;l.Color=c;l.Intensity=blink>0?1.8f:1.1f;l.BlinkIntervalSeconds=blink;l.BlinkLength=50f;}}
string AlertRoleName(IMyTerminalBlock b){string[]r=new string[]{"Battery","Uranium","Hydrogen","Oxygen","Cargo","Defence","Defense"};foreach(var x in r)if(LcdRole(b,x)||b.CustomName.IndexOf(x,StringComparison.OrdinalIgnoreCase)>=0)return x=="Defense"?"Defence":x;return"";}
void AlertData(string role,out string title,out string stat,out string detail,out double pct,out Color col,out float blink){title=role.Length>0?role.ToUpper():"AGM ALERT";stat="OK";detail="";pct=100;col=CLR_OK;blink=0f;if(role=="Battery"){double i=0,o=0;foreach(var b in _pBat){i+=b.CurrentInput;o+=b.CurrentOutput;}pct=_batPct;detail=pct.ToString("F0")+"%";if(_pBat.Count==0){stat="NO DATA";col=CLR_WARN;blink=2.5f;}else if(pct<=pBatOn){stat="CRITICAL";col=CLR_ERR;blink=.5f;}else if(i>o+.01&&pct<99){stat="CHARGING";col=CLR_CYAN;}else if(pct<=pBatOn+10){stat="LOW SOON";col=CLR_WARN;blink=2.5f;}else stat=pct>=95?"FULL":"OK";return;}if(role=="Uranium"){pct=pUWarn>0?Math.Min(_uranium/(pUWarn*2)*100,100):100;detail=Fmt(_uranium)+" kg";if(_pReact.Count==0){stat="NO DATA";col=CLR_WARN;blink=2.5f;}else if(_uranium<=0){stat="DEPLETED";col=CLR_ERR;blink=.5f;}else if(_uranium<pUWarn){stat="LOW";col=CLR_WARN;blink=2.5f;}else stat="PLENTY";return;}if(role=="Hydrogen"||role=="Oxygen"){bool h=role=="Hydrogen";pct=h?_h2Pct:_o2Pct;detail=pct.ToString("F0")+"%";if(pct<=0){stat="EMPTY";col=CLR_ERR;blink=.5f;}else if(pct<(h?pH2Crit:pO2Crit)){stat="CRITICAL";col=CLR_ERR;blink=.5f;}else if(pct>=90){stat="FULL";col=CLR_OK;}else if(_pGen.Count>0&&_ice>0&&pct>50){stat="REFILL";col=CLR_CYAN;}else if(pct<50){stat="HALF LOW";col=CLR_WARN;blink=2.5f;}else stat="OK";return;}if(role=="Cargo"){pct=_cargoPct;detail=pct.ToString("F0")+"%";if(pct>=pCargoCrit){stat="FULL";col=CLR_ERR;blink=.5f;}else if(pct>=50){stat="HALF FULL";col=CLR_WARN;blink=2.5f;}else stat="PLENTY";return;}if(role=="Defence"){int dam=0,on=0,armed=0,eng=0;foreach(var t in _pTurret){double ammo=0;if(t.HasInventory){_itmScr.Clear();t.GetInventory(0).GetItems(_itmScr);foreach(var x in _itmScr)ammo+=(double)x.Amount;}var lt=t as IMyLargeTurretBase;if(!t.IsFunctional)dam++;else if(t.Enabled){on++;if(ammo>0)armed++;if(lt!=null&&lt.HasTarget)eng++;}}pct=_pTurret.Count>0?armed*100.0/_pTurret.Count:0;detail=eng>0?eng+" targeting":armed+"/"+_pTurret.Count+" armed";if(dam>0){stat="DAMAGED";col=CLR_ERR;blink=.5f;}else if(_safeMode||on==0){stat=_safeMode?"SAFE MODE":"OFFLINE";col=CLR_CYAN;}else if(eng>0){stat="ENGAGING";col=CLR_WARN;blink=.5f;}else{stat="ONLINE";col=CLR_OK;}return;}stat=_alertLevel==2?"CRITICAL":_alertLevel==1?"WARNING":"OK";detail=_alertText;col=_alertLevel==2?CLR_ERR:_alertLevel==1?CLR_WARN:CLR_OK;blink=_alertLevel==2?.5f:_alertLevel==1?2.5f:0f;}
int GetPri(IMyTerminalBlock b){string n=b.CustomName.ToLower();int s=n.IndexOf("[p");if(s<0)return 500000+(int)(b.EntityId%100000);int e=n.IndexOf("]",s);if(e<0)return 500000+(int)(b.EntityId%100000);string t=n.Substring(s+2,e-s-2).Trim();if(t=="max")return 0;if(t=="min")return 999999;int v;return int.TryParse(t,out v)?v:500000+(int)(b.EntityId%100000);}
void SortPri(List<IMyTerminalBlock>l){l.Sort((a,b)=>GetPri(a).CompareTo(GetPri(b)));}
bool HasTag(IMyTerminalBlock b,string tag){return b.CustomName.IndexOf(tag,StringComparison.OrdinalIgnoreCase)>=0||b.CustomData.IndexOf(tag,StringComparison.OrdinalIgnoreCase)>=0;}
bool HasNameTag(IMyTerminalBlock b,string tag){return b.CustomName.IndexOf(tag,StringComparison.OrdinalIgnoreCase)>=0;}
bool HasDataTag(IMyTerminalBlock b,string tag){return b.CustomData.IndexOf(tag,StringComparison.OrdinalIgnoreCase)>=0;}
bool LcdRole(IMyTerminalBlock p,string role){foreach(var x in p.CustomData.Split('\n'))if(x.Trim().Equals(role,StringComparison.OrdinalIgnoreCase))return true;return false;}
bool IsExcluded(IMyTerminalBlock b){if(_excl.Contains(b.CubeGrid))return true;foreach(var ec in _exclConn)if(b.CubeGrid.IsSameConstructAs(ec.CubeGrid))return true;return false;}
bool IsPinnedStockLine(string line){string ln=line.Trim();int eq=ln.IndexOf('=');if(eq<0)return false;string amt=ln.Substring(eq+1).Trim();return amt.EndsWith("P",StringComparison.OrdinalIgnoreCase);}
void EnsureTemplateItems(IMyTerminalBlock b,string endTag,string[]names){string cd=b.CustomData;int end=cd.IndexOf(endTag,StringComparison.Ordinal);if(end<0)return;var add=new StringBuilder();foreach(var n in names){if(cd.IndexOf("\n"+n+"=",StringComparison.OrdinalIgnoreCase)>=0||cd.StartsWith(n+"=",StringComparison.OrdinalIgnoreCase))continue;add.Append(n);add.Append(InList(n,BOTTLE_NAMES)?"=20\n":"=0\n");}if(add.Length>0)b.CustomData=cd.Insert(end,add.ToString());}
void S1_FindItems(){foreach(var b in _all){if(!b.HasInventory)continue;for(int ii=0;ii<b.InventoryCount;ii++){_itmScr.Clear();b.GetInventory(ii).GetItems(_itmScr);foreach(var it in _itmScr){var id=it.Type;if(!_known.Contains(id)){_known.Add(id);Log("New: "+id.SubtypeId);}}}}}
void S3_Assign(){if(!autoAssign)return;if(assignNew){int nx=0;if(_oreC.Count==0&&nx<_untagged.Count){string a=" "+KW_ORE;if(oresIngotsOne)a+=" "+KW_INGOT;_untagged[nx].CustomName+=a;Log("Assigned: "+_untagged[nx].CustomName);nx++;}if(_cmpC.Count==0&&nx<_untagged.Count){_untagged[nx].CustomName+=" "+KW_COMP;Log("Assigned: "+_untagged[nx].CustomName);nx++;}if(_ammoC.Count==0&&nx<_untagged.Count){string a=" "+KW_AMMO;if(toolsAmmoBottlesOne){a+=" "+KW_TOOLS+" "+KW_BOTTLES;}Log("Assigned: "+_untagged[nx].CustomName+a);_untagged[nx].CustomName+=a;nx++;}if(_foodC.Count==0&&nx<_untagged.Count){string a=" "+KW_FOOD;if(foodSeedsIngOne){a+=" "+KW_SEEDS+" "+KW_ING;}Log("Assigned: "+_untagged[nx].CustomName+a);_untagged[nx].CustomName+=a;nx++;}}if(unassignEmpty){TryUnasgn(_oreC,KW_ORE);TryUnasgn(_ingC,KW_INGOT);TryUnasgn(_cmpC,KW_COMP);TryUnasgn(_ammoC,KW_AMMO);TryUnasgn(_toolC,KW_TOOLS);TryUnasgn(_botC,KW_BOTTLES);TryUnasgn(_foodC,KW_FOOD);TryUnasgn(_seedC,KW_SEEDS);TryUnasgn(_ingIC,KW_ING);}}
void TryUnasgn(List<IMyTerminalBlock>c,string kw){if(c.Count<=1)return;IMyTerminalBlock sched;if(_pendingUnasgn.TryGetValue(kw,out sched)){_pendingUnasgn.Remove(kw);if(sched.GetInventory(0).ItemCount==0&&!sched.CustomName.Contains("[P")){sched.CustomName=sched.CustomName.Replace(" "+kw,"").Replace(kw,"").TrimEnd();Log("Unassigned: "+sched.CustomName);}return;}int cnt=0;IMyTerminalBlock cand=null;foreach(var b in c){if(b.CustomName.Contains("[P"))continue;if(b.GetInventory(0).ItemCount==0){cand=b;cnt++;}}if(cnt>1&&cand!=null)_pendingUnasgn[kw]=cand;}
void S4_Stock(){foreach(var b in _stkC){string cd=b.CustomData;bool agm=cd.Contains(STOCK_START),goat=cd.Contains(GOAT_STOCK_START);if(!agm&&!goat){WriteStockTmpl(b);if(string.IsNullOrWhiteSpace(cd))Log("Stock tmpl written: "+b.CustomName);continue;}string st=agm?STOCK_START:GOAT_STOCK_START,en=agm?STOCK_END:GOAT_STOCK_END;if(agm)EnsureTemplateItems(b,STOCK_END,AMMO_NAMES);cd=b.CustomData;int s=cd.IndexOf(st),e=cd.IndexOf(en);if(s<0)continue;int nl=cd.IndexOf('\n',s);int bs=nl>=0?nl+1:s;int be=e>=0?e:cd.Length;if(bs>=be)continue;var inv=b.GetInventory(0);var stockLines=new List<string>(cd.Substring(bs,be-bs).Split('\n'));stockLines.Sort((a,z)=>IsPinnedStockLine(z).CompareTo(IsPinnedStockLine(a)));foreach(var line in stockLines){string ln=line.Trim();if(string.IsNullOrEmpty(ln)||ln.StartsWith("~")||ln.StartsWith("@")||ln.StartsWith("~~~"))continue;int eq=ln.IndexOf('=');if(eq<0)continue;string key=ln.Substring(0,eq).Trim(),amt=ln.Substring(eq+1).Trim();if(string.IsNullOrEmpty(key)||string.IsNullOrEmpty(amt))continue;bool pin=amt.Length>0&&(amt[amt.Length-1]=='P'||amt[amt.Length-1]=='p');if(pin)amt=amt.Substring(0,amt.Length-1).Trim();int mode=STOCK_NORMAL;bool fill=amt.ToLower()=="all";double want=0;if(fill){mode=STOCK_FILL;}else{if(amt.Length>0&&(amt[amt.Length-1]=='M'||amt[amt.Length-1]=='m')){mode=STOCK_MIN;amt=amt.Substring(0,amt.Length-1);}else if(amt.Length>0&&(amt[amt.Length-1]=='L'||amt[amt.Length-1]=='l')){mode=STOCK_LIMIT;amt=amt.Substring(0,amt.Length-1);}if(!double.TryParse(amt,out want))continue;if(want<0)continue;}MyItemType it=ResolveItem(key);string ts=it.ToString();double cur=(double)inv.GetItemAmount(it);if(mode==STOCK_LIMIT){if(cur<=want)continue;double ex=cur-want;foreach(var a in _src){if(a==b||!a.HasInventory)continue;var di=a.GetInventory(0);if(!InvNotFull(di))continue;ex-=XferType(ts,inv,di,ex);if(ex<=0)break;}continue;}if(mode==STOCK_FILL){if(!InvNotFull(inv))continue;foreach(var a in _src){if(a==b||!a.HasInventory)continue;var si2=a.GetInventory(0);double av=(double)si2.GetItemAmount(it);if(av<=0)continue;XferType(ts,si2,inv,av);if(!InvNotFull(inv))break;}continue;}if(cur<want){double nd=want-cur;foreach(var a in _src){if(a==b||!a.HasInventory)continue;var si2=a.GetInventory(0);double av=(double)si2.GetItemAmount(it);if(av<=0)continue;double moved=XferType(ts,si2,inv,Math.Min(nd,av));if(moved>0)Log("Stock +"+Fmt(moved)+" "+key);nd-=moved;if(nd<=0)break;}}if(mode==STOCK_NORMAL){cur=(double)inv.GetItemAmount(it);if(cur>want){double ex=cur-want;foreach(var a in _src){if(a==b||!a.HasInventory)continue;var di=a.GetInventory(0);if(!InvNotFull(di))continue;ex-=XferType(ts,inv,di,ex);if(ex<=0)break;}}}}}}
MyItemType ResolveItem(string key){key=StockAlias(key.Trim());if(key.Contains("/")){try{return MyItemType.Parse(OB+key);}catch{}}if(_known.Count>0){string[]tids2=new string[]{T_AMMO,T_COMP,T_TOOL,T_INGOT,T_ORE,T_CON,T_SEED,T_OXY,T_GAS,T_PHYS,T_DATA};foreach(var t in tids2){MyItemType c2;try{c2=MyItemType.Parse(OB+t+"/"+key);}catch{continue;}MyDefinitionId id2=c2;if(_known.Contains(id2))return c2;}}string[]order=new string[]{T_AMMO,T_COMP,T_INGOT,T_ORE,T_TOOL,T_CON,T_SEED,T_OXY,T_GAS,T_PHYS,T_DATA};foreach(var t in order){try{return MyItemType.Parse(OB+t+"/"+key);}catch{}}return MyItemType.MakeComponent(key);}
string StockAlias(string k){if(k.EndsWith("Ingot"))return T_INGOT+"/"+k.Substring(0,k.Length-5);if(k.EndsWith("Ore"))return T_ORE+"/"+k.Substring(0,k.Length-3);switch(k){case"Gravel":return T_INGOT+"/Stone";case"Scrap":return T_ORE+"/Scrap";case"ConstructionComp":return T_COMP+"/Construction";case"DetectorComponent":return T_COMP+"/Detector";case"GravityGenComponent":return T_COMP+"/GravityGenerator";case"MedicalComponent":return T_COMP+"/Medical";case"RadioCommComponent":return T_COMP+"/RadioCommunication";case"ReactorComponent":return T_COMP+"/Reactor";case"ThrustComponent":return T_COMP+"/Thrust";case"AutocannonMagazine":return T_AMMO+"/AutocannonClip";case"ArtilleryShell":return T_AMMO+"/LargeCalibreAmmo";case"AssaultCannonShell":return T_AMMO+"/MediumCalibreAmmo";case"Missile":return T_AMMO+"/Missile200mm";case"GatlingAmmo":return T_AMMO+"/NATO_25x184mm";case"LargeRailgunSabot":return T_AMMO+"/LargeRailgunAmmo";case"SmallRailgunSabot":return T_AMMO+"/SmallRailgunAmmo";case"FlareGunClip":return T_AMMO+"/FlareClip";case"PistolMagazine-S-10":return T_AMMO+"/SemiAutoPistolMagazine";case"PistolMagazine-S-10A":return T_AMMO+"/FullAutoPistolMagazine";case"PistolMagazine-S-10E":return T_AMMO+"/ElitePistolMagazine";case"RifleMagazine-MR-20":return T_AMMO+"/AutomaticRifleGun_Mag_20rd";case"RifleMagazine-MR-30E":return T_AMMO+"/UltimateAutomaticRifleGun_Mag_30rd";case"RifleMagazine-MR-50A":return T_AMMO+"/RapidFireAutomaticRifleGun_Mag_50rd";case"RifleMagazine-MR-8P":return T_AMMO+"/PreciseAutomaticRifleGun_Mag_5rd";case"AngleGrinder0":return T_TOOL+"/AngleGrinderItem";case"AngleGrinder1":return T_TOOL+"/AngleGrinder2Item";case"AngleGrinder2":return T_TOOL+"/AngleGrinder3Item";case"AngleGrinder3":return T_TOOL+"/AngleGrinder4Item";case"HandDrill0":return T_TOOL+"/HandDrillItem";case"HandDrill1":return T_TOOL+"/HandDrill2Item";case"HandDrill2":return T_TOOL+"/HandDrill3Item";case"HandDrill3":return T_TOOL+"/HandDrill4Item";case"Welder0":return T_TOOL+"/WelderItem";case"Welder1":return T_TOOL+"/Welder2Item";case"Welder2":return T_TOOL+"/Welder3Item";case"Welder3":return T_TOOL+"/Welder4Item";case"Rifle-MR-20":return T_TOOL+"/AutomaticRifleItem";case"Rifle-MR-30E":return T_TOOL+"/UltimateAutomaticRifleItem";case"Rifle-MR-50A":return T_TOOL+"/RapidFireAutomaticRifleItem";case"Rifle-MR-8P":return T_TOOL+"/PreciseAutomaticRifleItem";case"Pistol-S-10":return T_TOOL+"/SemiAutoPistolItem";case"Pistol-S-20A":return T_TOOL+"/FullAutoPistolItem";case"Pistol-S-10E":return T_TOOL+"/ElitePistolItem";case"RocketLauncher-PRO-1":return T_TOOL+"/AdvancedHandHeldLauncherItem";case"RocketLauncher-PO-1":return T_TOOL+"/BasicHandHeldLauncherItem";case"FlareGun":return T_TOOL+"/FlareGunItem";case"HydrogenBottle":return T_GAS+"/HydrogenBottle";case"OxygenBottle":return T_OXY+"/OxygenBottle";case"FruitSeeds":return T_SEED+"/Fruit";case"GrainSeeds":return T_SEED+"/Grain";case"MushroomSpores":return T_SEED+"/Mushrooms";case"VegetableSeeds":return T_SEED+"/Vegetables";case"Algae":return T_PHYS+"/Algae";case"Grain":return T_PHYS+"/Grain";case"SpaceCredit":return T_PHYS+"/SpaceCredit";case"Burrito":return T_CON+"/MealPack_Burrito";case"Chili":return T_CON+"/MealPack_Chili";case"Curry":return T_CON+"/MealPack_Curry";case"Dumplings":return T_CON+"/MealPack_Dumplings";case"Flatbread":return T_CON+"/MealPack_Flatbread";case"FrontierStew":return T_CON+"/MealPack_FrontierStew";case"FruitBar":return T_CON+"/MealPack_FruitBar";case"FruitPastry":return T_CON+"/MealPack_FruitPastry";case"GardenSlaw":return T_CON+"/MealPack_GardenSlaw";case"GreenPellets":return T_CON+"/MealPack_GreenPellets";case"KelpCrisp":return T_CON+"/MealPack_KelpCrisp";case"Lasagna":return T_CON+"/MealPack_Lasagna";case"Ramen":return T_CON+"/MealPack_Ramen";case"RedPellets":return T_CON+"/MealPack_RedPellets";case"SearedSabiroid":return T_CON+"/MealPack_SearedSabiroid";case"Spaghetti":return T_CON+"/MealPack_Spaghetti";case"SteakDinner":return T_CON+"/MealPack_SteakDinner";case"VeggieBurger":return T_CON+"/MealPack_VeggieBurger";}return k;}
void S5_Sort(){if(!_sortersOn)return;switch(_sortSub){case 0:Move(T_ORE,_oreC);break;case 1:Move(T_INGOT,_ingC);break;case 2:Move(T_COMP,_cmpC);break;case 3:Move(T_TOOL,_toolC);break;case 4:Move(T_AMMO,_ammoC);break;case 5:BottleSort(T_OXY);break;case 6:BottleSort(T_GAS);break;case 7:Move(T_DATA,_toolC);break;}_sortSub++;if(_sortSub>7)_sortSub=0;SortFood(T_CON);SortFood(T_PHYS);MoveOpt(T_SEED,_seedC);}
void BottleSort(string tid){if(_pGen.Count==0){Move(tid,_botC);return;}RefillBottlesOf(tid);_bottleWait++;if(_bottleWait>=2){PullBottlesFromGens(tid);_bottleWait=0;}}
void PullBottlesFromGens(string tid){if(_botC.Count==0)return;foreach(var g in _pGen){var s=g.GetInventory(0);_itmScr.Clear();s.GetItems(_itmScr);for(int i=_itmScr.Count-1;i>=0;i--){if(!_itmScr[i].Type.TypeId.ToString().Contains(tid))continue;foreach(var b in _botC){var d=b.GetInventory(0);if(!InvNotFull(d))continue;s.TransferItemTo(d,i,null,true,null);break;}}}}
void Move(string tid,List<IMyTerminalBlock>dests){if(dests.Count==0)return;IMyInventory dInv=null;for(int i=0;i<dests.Count;i++){if(InvNotFull(dests[i].GetInventory(0))){dInv=dests[i].GetInventory(0);break;}}if(dInv==null)return;for(int si=0;si<_src.Count;si++){var sb=_src[si];if(!sb.HasInventory)continue;if(IsCorrect(sb,tid))continue;var sInv=sb.GetInventory(0);var items=new List<MyInventoryItem>();sInv.GetItems(items);for(int ii=items.Count-1;ii>=0;ii--){if(!items[ii].Type.TypeId.ToString().Contains(tid))continue;if(!InvNotFull(dInv)){dInv=null;for(int d=0;d<dests.Count;d++){if(InvNotFull(dests[d].GetInventory(0))){dInv=dests[d].GetInventory(0);break;}}if(dInv==null)return;}var dItems=new List<MyInventoryItem>();dInv.GetItems(dItems);int ds=-1;for(int d=0;d<dItems.Count;d++){if(dItems[d].Type==items[ii].Type){ds=d;break;}}if(ds>=0)sInv.TransferItemTo(dInv,ii,ds,true,null);else sInv.TransferItemTo(dInv,ii,null,true,null);}}}
void MoveOpt(string tid,List<IMyTerminalBlock>dests){if(dests.Count>0)Move(tid,dests);}
bool IsCorrect(IMyTerminalBlock b,string tid){if(tid==T_ORE)return HasTag(b,KW_ORE);if(tid==T_INGOT)return HasTag(b,KW_INGOT);if(tid==T_COMP)return HasTag(b,KW_COMP);if(tid==T_AMMO)return HasTag(b,KW_AMMO);if(tid==T_TOOL)return HasTag(b,KW_TOOLS);if(tid==T_OXY||tid==T_GAS)return HasTag(b,KW_BOTTLES);if(tid==T_SEED)return HasTag(b,KW_SEEDS);if(tid==T_CON)return HasTag(b,KW_TOOLS)||HasTag(b,KW_FOOD)||HasTag(b,KW_ING);if(tid==T_PHYS)return HasTag(b,KW_ING)||HasTag(b,KW_TOOLS);return false;}
List<IMyTerminalBlock>FoodDest(string tid,string sub){if(tid.Contains(T_PHYS)){foreach(var s in PHYS_ING)if(sub==s)return _ingIC.Count>0?_ingIC:null;return null;}foreach(var s in ING_SUBS)if(sub==s)return _ingIC.Count>0?_ingIC:(_foodC.Count>0?_foodC:null);return _foodC.Count>0?_foodC:null;}
void SortFood(string tid){for(int si=0;si<_src.Count;si++){var sb=_src[si];if(!sb.HasInventory)continue;var sInv=sb.GetInventory(0);var items=new List<MyInventoryItem>();sInv.GetItems(items);for(int ii=items.Count-1;ii>=0;ii--){var it=items[ii];string typeId=it.Type.TypeId.ToString(),sub=it.Type.SubtypeId.ToString();if(!typeId.Contains(tid))continue;var dl=FoodDest(typeId,sub);if(dl==null)continue;bool ok=false;foreach(var d in dl)if(sb==d){ok=true;break;}if(ok)continue;IMyInventory dInv=null;foreach(var d in dl)if(InvNotFull(d.GetInventory(0))){dInv=d.GetInventory(0);break;}if(dInv==null)continue;var di=new List<MyInventoryItem>();dInv.GetItems(di);int ds=-1;for(int d=0;d<di.Count;d++)if(di[d].Type==it.Type){ds=d;break;}if(ds>=0)sInv.TransferItemTo(dInv,ii,ds,true,null);else sInv.TransferItemTo(dInv,ii,null,true,null);}}}
void S6_Balance(){if(!balanceContainers)return;switch(_balSub){case 0:BalCat(_oreC,T_ORE);break;case 1:BalCat(_ingC,T_INGOT);break;case 2:BalCat(_cmpC,T_COMP);break;case 3:BalCat(_ammoC,T_AMMO);break;case 4:BalCat(_toolC,T_TOOL);break;case 5:BalCat(_botC,T_GAS);break;}_balSub++;if(_balSub>5)_balSub=0;}
void BalCat(List<IMyTerminalBlock>c,string tf){var sg=new List<IMyTerminalBlock>();foreach(var b in c)if(b.InventoryCount==1&&b.CubeGrid.IsSameConstructAs(Me.CubeGrid))sg.Add(b);if(sg.Count<2)return;var tot=new Dictionary<MyItemType,double>();var sc=new List<MyInventoryItem>();foreach(var b in sg){sc.Clear();b.GetInventory(0).GetItems(sc);foreach(var it in sc){if(!it.Type.TypeId.ToString().Contains(tf))continue;if(tot.ContainsKey(it.Type))tot[it.Type]+=(double)it.Amount;else tot[it.Type]=(double)it.Amount;}}var tgt=new Dictionary<MyItemType,double>();foreach(var p in tot)tgt[p.Key]=Math.Floor(p.Value/sg.Count);for(int si=0;si<sg.Count;si++){var sInv=sg[si].GetInventory(0);sc.Clear();sInv.GetItems(sc);var hv=new Dictionary<MyItemType,double>();foreach(var it in sc){if(hv.ContainsKey(it.Type))hv[it.Type]+=(double)it.Amount;else hv[it.Type]=(double)it.Amount;}foreach(var p in tot){double here=0;hv.TryGetValue(p.Key,out here);double tg=0;tgt.TryGetValue(p.Key,out tg);if(here<=tg+1)continue;for(int di=0;di<sg.Count;di++){if(di==si)continue;var dInv=sg[di].GetInventory(0);double there=(double)dInv.GetItemAmount(p.Key);if(there>=tg-1)continue;double amt=Math.Min(tg-there,here-tg);if(amt<=0)continue;XferType(p.Key.ToString(),sInv,dInv,amt);here-=amt;if(here<=tg+1)break;}}}}
void S7_Turrets(){if(!fillTurrets||_guns.Count==0)return;foreach(var gun in _guns){if(gun==null||!gun.IsFunctional||!gun.HasInventory)continue;var dst=gun.GetInventory(0);foreach(var p in TURRET_AMMO_TARGETS){MyItemType it;try{it=MyItemType.MakeAmmo(p.Key);}catch{continue;}if(!dst.CanItemsBeAdded((MyFixedPoint)1,it))continue;double cur=(double)dst.GetItemAmount(it),need=p.Value-cur;if(need<=0)continue;need=PullAmmoToTurret(it,dst,need,_ammoC);if(need>0)PullAmmoToTurret(it,dst,need,_src);}}}
double PullAmmoToTurret(MyItemType it,IMyInventory dst,double need,List<IMyTerminalBlock>srcs){string ts=it.ToString();foreach(var b in srcs){if(need<=0)break;if(b==null||!b.HasInventory)continue;var src=b.GetInventory(0);if(src==dst)continue;double av=(double)src.GetItemAmount(it);if(av<=0)continue;need-=XferType(ts,src,dst,Math.Min(need,av));}return need;}
void S8_Ice(){if(!iceBalance||_pGen.Count==0)return;PushToMachines(MyItemType.MakeOre("Ice"),_pGen.ConvertAll(g=>g as IMyTerminalBlock));}
double ReactorTarget(IMyReactor r){if(r.BlockDefinition.SubtypeId.IndexOf("Large",StringComparison.OrdinalIgnoreCase)>=0)return pULarge;return r.CubeGrid.GridSizeEnum==MyCubeSize.Small?pUSmallGrid:pUSmall;}
void S9_Uranium(){if(!uraniumBalance||_pReact.Count==0)return;var it=MyItemType.MakeIngot("Uranium");foreach(var r in _pReact){double target=ReactorTarget(r),need=target-(double)r.GetInventory(0).GetItemAmount(it);if(need<=0)continue;foreach(var b in _ingC){if(need<=0)break;var s=b.GetInventory(0);double a=(double)s.GetItemAmount(it);if(a>0)need-=XferType(it.ToString(),s,r.GetInventory(0),Math.Min(a,need));}}}
void PushToMachines(MyItemType it,List<IMyTerminalBlock>mach){if(mach.Count==0)return;string ts=it.ToString();double[]cur=new double[mach.Count];double inMach=0;for(int i=0;i<mach.Count;i++){if(!mach[i].HasInventory)continue;cur[i]=(double)mach[i].GetInventory(0).GetItemAmount(it);inMach+=cur[i];}double inStore=0;foreach(var b in _all){bool m=false;foreach(var mc in mach)if(b==mc){m=true;break;}if(m||!b.HasInventory)continue;inStore+=(double)b.GetInventory(0).GetItemAmount(it);}if(inStore<=0)return;double tgt=(inMach+inStore)/mach.Count;for(int mi=0;mi<mach.Count;mi++){if(!mach[mi].HasInventory)continue;double nd=tgt-cur[mi];if(nd<=1)continue;var mInv=mach[mi].GetInventory(0);foreach(var b in _all){bool m=false;foreach(var mc in mach)if(b==mc){m=true;break;}if(m||!b.HasInventory)continue;var sInv=b.GetInventory(0);double av=(double)sInv.GetItemAmount(it);if(av<=0)continue;nd-=XferType(ts,sInv,mInv,Math.Min(nd,av));if(nd<=1)break;}}}
void S10_Amounts(){_gAmt.Clear();foreach(var b in _all){if(!b.HasInventory)continue;for(int ii=0;ii<b.InventoryCount;ii++){_itmScr.Clear();b.GetInventory(ii).GetItems(_itmScr);foreach(var it in _itmScr){if(_gAmt.ContainsKey(it.Type))_gAmt[it.Type]+=(double)it.Amount;else _gAmt[it.Type]=(double)it.Amount;}}}}
List<IMyTerminalBlock>ItemDest(MyInventoryItem x){string t=x.Type.TypeId.ToString(),s=x.Type.SubtypeId.ToString();if(t.Contains(T_COMP))return _cmpC;if(t.Contains(T_AMMO))return _ammoC;if(t.Contains(T_TOOL)||t.Contains(T_DATA))return _toolC;if(t.Contains(T_OXY)||t.Contains(T_GAS))return _botC;if(t.Contains(T_SEED))return _seedC;if(t.Contains(T_CON)||t.Contains(T_PHYS))return FoodDest(t,s);return null;}
void S12_AsmClean(){if(!cleanAsm)return;foreach(var a in _asm){var inv=a.GetInventory(1);if((float)inv.CurrentVolume==0f)continue;_itmScr.Clear();inv.GetItems(_itmScr);for(int i=_itmScr.Count-1;i>=0;i--){var dl=ItemDest(_itmScr[i]);if(dl==null)continue;foreach(var c in dl){var d=c.GetInventory(0);if(!InvNotFull(d))continue;inv.TransferItemTo(d,i,null,true,null);break;}}}}
void CleanRefineries(List<IMyRefinery>all){foreach(var r in all){if(r.InventoryCount<2)continue;var s=r.GetInventory(1);_itmScr.Clear();s.GetItems(_itmScr);for(int i=_itmScr.Count-1;i>=0;i--)foreach(var c in _ingC){if(!InvNotFull(c.GetInventory(0)))continue;if(s.TransferItemTo(c.GetInventory(0),i,null,true,null))break;}}}
void FeedRefineries(List<IMyRefinery>all){foreach(var r in all){if(!r.IsFunctional||!r.Enabled)continue;var d=r.GetInventory(0);if((double)d.CurrentVolume>(double)d.MaxVolume*.45)continue;MyItemType best=default(MyItemType);bool found=false;double low=double.MaxValue,av=0;foreach(var c in _oreC){_itmScr.Clear();c.GetInventory(0).GetItems(_itmScr);foreach(var q in _itmScr){if(!q.Type.TypeId.ToString().Contains(T_ORE)||q.Type.SubtypeId.ToString()=="Ice"||!d.CanItemsBeAdded((MyFixedPoint)1,q.Type))continue;MyDefinitionId ing=default(MyDefinitionId);MyDefinitionId.TryParse(OB+T_INGOT+"/"+q.Type.SubtypeId,out ing);double h=0;_gAmt.TryGetValue(ing,out h);if(h<low){found=true;low=h;best=q.Type;av=(double)q.Amount;}}}if(!found)continue;double need=Math.Min(av,10000);foreach(var c in _oreC){if(need<=0)break;need-=XferType(best.ToString(),c.GetInventory(0),d,need);}}}
void S15_OreBalance(){if(!oreBalance)return;var all=new List<IMyRefinery>();all.AddRange(_ref);all.AddRange(_arc);if(all.Count==0)return;CleanRefineries(all);FeedRefineries(all);if(all.Count<2)return;var types=new List<MyItemType>();var tmp=new List<MyInventoryItem>();foreach(var r in all){tmp.Clear();r.GetInventory(0).GetItems(tmp);foreach(var it in tmp)if(!types.Contains(it.Type))types.Add(it.Type);}foreach(var ore in types){double tot=0;foreach(var r in all)tot+=(double)r.GetInventory(0).GetItemAmount(ore);if(tot<=0)continue;double tgt=tot/all.Count;for(int si=0;si<all.Count;si++){double h=(double)all[si].GetInventory(0).GetItemAmount(ore);if(h<=tgt+1)continue;for(int di=0;di<all.Count;di++){if(di==si)continue;var dInv=all[di].GetInventory(0);if(!InvNotFull(dInv))continue;double there=(double)dInv.GetItemAmount(ore);if(there>=tgt-1)continue;double am=Math.Min(tgt-there,h-tgt);if(am<=0)continue;XferType(ore.ToString(),all[si].GetInventory(0),dInv,am);h-=am;if(h<=tgt+1)break;}}}}
void S16_RefSort(){var all=new List<IMyRefinery>();all.AddRange(_ref);all.AddRange(_arc);foreach(var r in all){var items=new List<MyInventoryItem>();r.GetInventory(0).GetItems(items);if(items.Count<2)continue;int bi=0;double bs=double.MaxValue;for(int i=0;i<items.Count;i++){string s=items[i].Type.SubtypeId.ToString();MyDefinitionId id=default(MyDefinitionId);MyDefinitionId.TryParse(OB+T_INGOT+"/"+s,out id);double h=0;_gAmt.TryGetValue(id,out h);if(h<bs){bs=h;bi=i;}}if(bi!=0)r.GetInventory(0).TransferItemTo(r.GetInventory(0),bi,0,true,null);}}
void S17_InternalSort(){foreach(var b in _typedC){var inv=b.GetInventory(0);_itmScr.Clear();inv.GetItems(_itmScr);if(_itmScr.Count<2)continue;bool mg=true;int gd=0;while(mg&&gd<50){mg=false;gd++;_itmScr.Clear();inv.GetItems(_itmScr);var fs=new Dictionary<MyItemType,int>();for(int i=0;i<_itmScr.Count;i++){if(!fs.ContainsKey(_itmScr[i].Type))fs[_itmScr[i].Type]=i;}for(int i=_itmScr.Count-1;i>=0;i--){int f=fs[_itmScr[i].Type];if(i!=f){inv.TransferItemTo(inv,i,f,true,null);mg=true;}}}}if(showFill)UpdateFillNames();}
void UpdateFillNames(){foreach(var b in _typedC){var inv=b.GetInventory(0);float p=(float)inv.MaxVolume>0f?(float)inv.CurrentVolume/(float)inv.MaxVolume*100f:0f;string n=b.CustomName;int lb=n.LastIndexOf(" (");int rb=n.LastIndexOf("%)");if(lb>=0&&rb>lb)n=n.Substring(0,lb);b.CustomName=n+" ("+((int)p)+"%)";}}
void DrawInventoryStep(){_lcdRescanTimer++;if(_lcdRescanTimer>=LCD_RESCAN){_lcdRescanTimer=0;BindLcds();}if(_displaySub==0)CDrawInv(_sfOre,"ORE STOCK",ORE_NAMES,T_ORE,CLR_ACCENT,_oreC);else if(_displaySub==1)CDrawInv(_sfIngot,"INGOT STOCK",INGOT_NAMES,T_INGOT,CLR_OK,_ingC);else if(_displaySub==2)CDrawInv(_sfComp,"COMPONENTS",COMP_NAMES,T_COMP,new Color(80,160,255),_cmpC);else if(_displaySub==3)CDrawInv(_sfAmmo,"AMMUNITION",AMMO_NAMES,T_AMMO,CLR_ERR,_ammoC);else if(_displaySub==4)CDrawKnown(_sfTools,"TOOLS & ITEMS",T_TOOL,new Color(180,120,255),_toolC,0);else if(_displaySub==5)CDrawKnown(_sfFood,"FOOD & DRINKS",T_CON,new Color(255,180,60),_foodC,1);else if(_displaySub==6)CDrawKnown(_sfBot,"BOTTLES",T_GAS,new Color(80,200,255),_botC,2);else if(_displaySub==7)CDrawKnown(_sfSeed,"SEEDS",T_SEED,new Color(100,220,80),_seedC,0);else CDrawKnown(_sfIngI,"INGREDIENTS",T_CON,new Color(200,140,80),_ingIC,3);_displaySub++;if(_displaySub>8)_displaySub=0;}
bool InvNotFull(IMyInventory inv){float c=(float)inv.CurrentVolume,m=(float)inv.MaxVolume;if(m<=0)return false;return m*0.02f<(float)invBuffer?c<m*0.98f:c<m-(float)invBuffer;}
string InvName(IMyInventory x){foreach(var b in _all)for(int i=0;i<b.InventoryCount;i++)if(b.GetInventory(i)==x)return b.CustomName;return"?";}
double XferType(string ts,IMyInventory src,IMyInventory dst,double max){_itmScr.Clear();src.GetItems(_itmScr);double mv=0;for(int i=_itmScr.Count-1;i>=0;i--){if(!_itmScr[i].Type.ToString().Contains(ts.Contains("/")?ts:"/"+ts))continue;MyFixedPoint a=(MyFixedPoint)Math.Min((double)_itmScr[i].Amount,max-mv);if((double)a<=0)continue;if(src.TransferItemTo(dst,i,null,true,a)){mv+=(double)a;Log(DateTime.Now.ToString("HH:mm")+" "+_itmScr[i].Type.SubtypeId+" "+InvName(src)+" > "+InvName(dst));}if(mv>=max)break;}return mv;}
void Log(string m){_log.Add(m);if(_log.Count>20)_log.RemoveAt(0);}
string Fmt(double v){if(v>=1000000)return(v/1000000.0).ToString("F2")+"M";if(v>=1000)return(v/1000.0).ToString("F1")+"k";return((int)v).ToString();}
void AutoLcdWatch(){_lcdWatch++;if(_lcdWatch<60)return;_lcdWatch=0;string sig=LcdSignature();if(sig==_lcdSig)return;_booting=true;_bootPhase=0;Log("LCD layout changed - boot refresh.");}
string LcdSignature(){var pans=new List<IMyTextPanel>();GridTerminalSystem.GetBlocksOfType<IMyTextPanel>(pans,p=>(HasNameTag(p,AGM_TAG)||HasTag(p,P_ALERT))&&!IsExcluded(p));pans.Sort((a,b)=>a.EntityId.CompareTo(b.EntityId));int h=17;foreach(var p in pans){h=h*31+(int)(p.EntityId&0x7fffffff);h=h*31+p.CustomName.GetHashCode();h=h*31+p.CustomData.GetHashCode();h=h*31+(p.IsWorking?1:0);}return pans.Count+":"+h;}
void ResetLcds(){_initLcds.Clear();_drawCursor.Clear();_displaySub=0;_lcdRescanTimer=0;}
void SetupSurf(IMyTextSurface s){var p=s as IMyTextPanel;long id=p!=null?p.EntityId:Me.EntityId;if(_initLcds.Contains(id)&&s.ContentType==ContentType.SCRIPT&&string.IsNullOrEmpty(s.Script))return;s.ContentType=ContentType.SCRIPT;s.Script="";s.ScriptBackgroundColor=CLR_BG;s.BackgroundColor=CLR_BG;s.BackgroundAlpha=0;s.FontColor=CLR_WHITE;s.FontSize=1f;s.TextPadding=0f;try{s.ClearImagesFromSelection();}catch{}_initLcds.Add(id);}
void DrawBar(MySpriteDrawFrame f,Vector2 pos,float bw,float bh,double cur,double max,Color col){float r=(max>0)?(float)Math.Min(cur/max,1.0):0f;f.Add(new MySprite(SpriteType.TEXTURE,"SquareSimple",pos+new Vector2(bw*0.5f,bh*0.5f),new Vector2(bw,bh),CLR_BAR_BG));if(r>0f)f.Add(new MySprite(SpriteType.TEXTURE,"SquareSimple",pos+new Vector2(bw*r*0.5f,bh*0.5f),new Vector2(bw*r,bh),col));}
void CT(MySpriteDrawFrame f,string s,Vector2 p,Color c,float z,TextAlignment a){var x=MySprite.CreateText(s,"Monospace",c,z,a);x.Position=p;f.Add(x);}
void CR(MySpriteDrawFrame f,Vector2 p,Vector2 z,Color c){f.Add(new MySprite(SpriteType.TEXTURE,"SquareSimple",p,z,c));}
string CN(string s){var b=new StringBuilder();for(int i=0;i<s.Length;i++){char c=s[i];if(c=='_'){b.Append(' ');continue;}if(i>0&&char.IsUpper(c)&&char.IsLower(s[i-1]))b.Append(' ');b.Append(c);}return b.ToString().Replace("Meal Pack ","");}
void CDrawPB(){var p=Me as IMyTextSurfaceProvider;if(p==null||p.SurfaceCount==0)return;var sf=p.GetSurface(0);SetupSurf(sf);Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);CT(f,"AGM",v+z*.5f-new Vector2(0,28),CLR_ACCENT,1.6f,TextAlignment.CENTER);CT(f,"AUTOGRID MANAGER v3.0",v+z*.5f+new Vector2(0,42),CLR_DIM,.34f,TextAlignment.CENTER);}}
void CDrawMain(){int si=NextSurface(_sfMain,"main");if(si<0)return;var sf=_sfMain[si];SetupSurf(sf);Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y;using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);CR(f,v+new Vector2(w*.5f,h*.07f),new Vector2(w,h*.14f),CLR_PANEL);CT(f,"AUTOGRID MANAGER",v+new Vector2(w*.5f,h*.025f),CLR_ACCENT,.62f,TextAlignment.CENTER);CT(f,"SYSTEMS",v+new Vector2(w*.04f,h*.24f),CLR_ACCENT,.40f,TextAlignment.LEFT);CR(f,v+new Vector2(w*.5f,h*.30f),new Vector2(w*.94f,2),CLR_ACCENT);CT(f,"Inventory",v+new Vector2(w*.05f,h*.37f),CLR_DIM,.30f,TextAlignment.LEFT);CT(f,_all.Count.ToString(),v+new Vector2(w*.27f,h*.37f),CLR_WHITE,.38f,TextAlignment.RIGHT);CT(f,"Assemblers",v+new Vector2(w*.39f,h*.37f),CLR_DIM,.30f,TextAlignment.LEFT);CT(f,_asm.Count.ToString(),v+new Vector2(w*.61f,h*.37f),CLR_WHITE,.38f,TextAlignment.RIGHT);CT(f,"Refineries",v+new Vector2(w*.72f,h*.37f),CLR_DIM,.30f,TextAlignment.LEFT);CT(f,(_ref.Count+_arc.Count).ToString(),v+new Vector2(w*.95f,h*.37f),CLR_WHITE,.38f,TextAlignment.RIGHT);CT(f,"STORAGE",v+new Vector2(w*.04f,h*.55f),CLR_ACCENT,.40f,TextAlignment.LEFT);CR(f,v+new Vector2(w*.5f,h*.61f),new Vector2(w*.94f,2),CLR_ACCENT);CT(f,"Ore "+_oreC.Count+"   Ingot "+_ingC.Count+"   Component "+_cmpC.Count+"   Ammo "+_ammoC.Count,v+new Vector2(w*.05f,h*.69f),CLR_WHITE,.31f,TextAlignment.LEFT);CT(f,"Tools "+_toolC.Count+"   Bottles "+_botC.Count+"   Food "+_foodC.Count+"   Seeds "+_seedC.Count+"   Ingredients "+_ingIC.Count,v+new Vector2(w*.05f,h*.78f),CLR_WHITE,.28f,TextAlignment.LEFT);CR(f,v+new Vector2(w*.5f,h-14),new Vector2(w,28),CLR_PANEL);CT(f,"AUTOGRID MANAGER v3.0",v+new Vector2(w*.5f,h-22),CLR_DIM,.28f,TextAlignment.CENTER);}}
void PScr(List<IMyTextSurface>ss,string title,List<string>lines,Color col){int si=NextSurface(ss,title);if(si<0)return;var sf=ss[si];SetupSurf(sf);int rows=12,pages=Math.Max(1,(int)Math.Ceiling(lines.Count/(double)rows)),pg=GetLcdPage(sf);if(pg>=pages){pg=0;SetLcdPage(sf,0);}Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y,rh=(h-70)/rows;using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);int st=pg*rows;for(int j=0;j<rows&&st+j<lines.Count;j++){string s=lines[st+j];Color c=s.Contains("CRIT")||s.Contains("FULL")||s.Contains("DEPLETED")||s.Contains("LEAK")?CLR_ERR:s.Contains("LOW")||s.Contains("OFFLINE")||s.Contains("WARN")?CLR_WARN:CLR_WHITE;CT(f,s,v+new Vector2(w*.04f,46+j*rh),c,rh<28?.25f:.31f,TextAlignment.LEFT);}CR(f,v+new Vector2(w*.5f,18),new Vector2(w,36),CLR_PANEL);CT(f,title,v+new Vector2(w*.5f,7),col,.52f,TextAlignment.CENTER);if(pages>1)CT(f,"P"+(pg+1)+"/"+pages,v+new Vector2(w*.97f,7),col,.28f,TextAlignment.RIGHT);CR(f,v+new Vector2(w*.5f,h-11),new Vector2(w,22),CLR_PANEL);CT(f,"AUTOGRID MANAGER v3.0",v+new Vector2(w*.5f,h-18),CLR_DIM,.25f,TextAlignment.CENTER);}}
void P2Display(){if(_p2Display==0)DrawPower();else if(_p2Display==1)DrawFuel();else if(_p2Display==2)DrawDock();else if(_p2Display==3)DrawDef();else if(_p2Display==4)DrawDock();else if(_p2Display==5)DrawProd();else if(_p2Display==6)DrawDock();else DrawLog();_p2Display++;if(_p2Display>7)_p2Display=0;}
void FastLiveDashboards(){P2Display();}
string PBar(double p){int n=(int)Math.Round(MathHelper.Clamp((float)p,0,100)/10);return"["+new string('|',n)+new string('.',10-n)+"] "+p.ToString("F1")+"%";}
void DScreen(List<IMyTextSurface>ss,string title,List<IMyTerminalBlock>bs,List<string>tx,List<double>va,List<double>mx,List<int>st,Color ac){int si=NextSurface(ss,title);if(si<0)return;var sf=ss[si];SetupSurf(sf);int rows=10,pages=Math.Max(1,(int)Math.Ceiling(bs.Count/(double)rows)),pg=GetLcdPage(sf);if(pg>=pages){pg=0;SetLcdPage(sf,0);}Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y,rh=(h-64)/rows;using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);int q=pg*rows;for(int j=0;j<rows&&q+j<bs.Count;j++){int i=q+j;float y=v.Y+42+j*rh,ic=Math.Min(24,rh*.8f);try{f.Add(new MySprite(SpriteType.TEXTURE,bs[i].BlockDefinition.ToString(),new Vector2(v.X+w*.04f,y+rh*.38f),new Vector2(ic,ic),Color.White));}catch{}CT(f,tx[i],new Vector2(v.X+w*.08f,y),CLR_WHITE,rh<31?.25f:.3f,TextAlignment.LEFT);double m=mx[i]>0?mx[i]:1,r=Math.Min(va[i]/m,1);CR(f,new Vector2(v.X+w*.67f,y+rh*.32f),new Vector2(w*.28f,10),CLR_BAR_BG);if(r>0)CR(f,new Vector2(v.X+w*.53f+w*.28f*(float)r*.5f,y+rh*.32f),new Vector2(w*.28f*(float)r,10),ac);Color c=st[i]==2?CLR_ERR:st[i]==1?CLR_WARN:CLR_OK;CR(f,new Vector2(v.X+w*.91f,y+rh*.32f),new Vector2(13,13),c);CT(f,mx[i]>1?Fmt(va[i]):(va[i]>0?"ON":"OFF"),new Vector2(v.X+w*.98f,y),CLR_DIM,.25f,TextAlignment.RIGHT);}CR(f,v+new Vector2(w*.5f,18),new Vector2(w,36),CLR_PANEL);CT(f,title,v+new Vector2(w*.5f,7),ac,.52f,TextAlignment.CENTER);if(pages>1)CT(f,"P"+(pg+1)+"/"+pages,v+new Vector2(w*.97f,7),ac,.28f,TextAlignment.RIGHT);CR(f,v+new Vector2(w*.5f,h-11),new Vector2(w,22),CLR_PANEL);CT(f,"Green Online   Amber Offline/Depleted   Red Damaged",v+new Vector2(w*.5f,h-18),CLR_DIM,.22f,TextAlignment.CENTER);}}
int BState(IMyTerminalBlock b,bool depleted){var f=b as IMyFunctionalBlock;return f==null||!f.IsFunctional?2:!f.Enabled||depleted?1:0;}
float PowerDots(MySpriteDrawFrame f,string name,List<int>st,Vector2 v,float w,float y){return StateDots(f,name,st,v,w,y,"ONLINE");}
float StateDots(MySpriteDrawFrame f,string name,List<int>st,Vector2 v,float w,float y,string word){int on=0;foreach(var state in st)if(state==0)on++;CT(f,name,v+new Vector2(w*.05f,y),CLR_WHITE,.44f,TextAlignment.LEFT);CT(f,on+"/"+st.Count+" "+word,v+new Vector2(w*.95f,y),on==st.Count?CLR_OK:CLR_WARN,.40f,TextAlignment.RIGHT);float x=v.X+w*.055f,sy=v.Y+y+34,sz=Math.Min(24,w*.045f),gap=sz+9;int rows=1;for(int i=0;i<st.Count;i++){if(x+sz>v.X+w*.96f){x=v.X+w*.055f;sy+=sz+8;rows++;}Color c=st[i]==2?CLR_ERR:st[i]==1?CLR_WARN:CLR_OK;CR(f,new Vector2(x+sz*.5f,sy+sz*.5f),new Vector2(sz,sz),c);x+=gap;}return 38+rows*(sz+8);}
void PowerBar(MySpriteDrawFrame f,string name,double cur,double max,Vector2 v,float w,float y,Color c,string unit){double pc=max>0?cur/max*100:0;CT(f,name,v+new Vector2(w*.05f,y),CLR_WHITE,.40f,TextAlignment.LEFT);CT(f,pc.ToString("F0")+"%",v+new Vector2(w*.95f,y),c,.40f,TextAlignment.RIGHT);DrawBar(f,v+new Vector2(w*.05f,y+28),w*.90f,18,cur,max,c);string raw=Fmt(cur)+" / "+Fmt(max)+(unit.Length>0?" "+unit:"");CT(f,raw,v+new Vector2(w*.95f,y+52),CLR_DIM,.30f,TextAlignment.RIGHT);}
void DrawPower(){int si=NextSurface(_sfPower,"power");if(si<0)return;var sf=_sfPower[si];SetupSurf(sf);Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y;var rs=new List<int>();var hs=new List<int>();var u=MyItemType.MakeIngot("Uranium");foreach(var x in _pReact)rs.Add(BState(x,(double)x.GetInventory(0).GetItemAmount(u)<=0));foreach(var x in _pH2Eng)hs.Add(BState(x,false));double bc=0,bm=0,bo=0,bom=0,so=0,som=0,wo=0,wom=0;foreach(var x in _pBat){bc+=x.CurrentStoredPower;bm+=x.MaxStoredPower;bo+=x.CurrentOutput;bom+=x.MaxOutput;}foreach(var x in _pSolar){so+=x.CurrentOutput;som+=x.MaxOutput;}foreach(var x in _pWind){wo+=x.CurrentOutput;wom+=x.MaxOutput;}using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);CR(f,v+new Vector2(w*.5f,23),new Vector2(w,46),CLR_PANEL);CT(f,"POWER",v+new Vector2(w*.5f,7),CLR_OK,.72f,TextAlignment.CENTER);float y=62;if(rs.Count>0)y+=PowerDots(f,"REACTORS",rs,v,w,y)+6;if(hs.Count>0)y+=PowerDots(f,"HYDROGEN ENGINES",hs,v,w,y)+6;CR(f,v+new Vector2(w*.5f,y),new Vector2(w*.9f,2),CLR_ACCENT);y+=14;if(_pBat.Count>0){PowerBar(f,"BATTERY CHARGE",bc,bm,v,w,y,CLR_OK,"MWh");y+=60;PowerBar(f,"BATTERY OUTPUT",bo,bom,v,w,y,new Color(80,200,255),"MW");y+=60;}if(_pSolar.Count>0){PowerBar(f,"SOLAR OUTPUT",so,som,v,w,y,CLR_WARN,"MW");y+=60;}if(_pWind.Count>0)PowerBar(f,"WIND OUTPUT",wo,wom,v,w,y,new Color(180,120,255),"MW");CR(f,v+new Vector2(w*.5f,h-13),new Vector2(w,26),CLR_PANEL);CT(f,"GREEN READY   AMBER ATTENTION   RED DAMAGED",v+new Vector2(w*.5f,h-22),CLR_DIM,.30f,TextAlignment.CENTER);}}
string BName(IMyTerminalBlock b,string key){string cd=b.CustomData;int p=cd.IndexOf(key+"=",StringComparison.OrdinalIgnoreCase);if(p<0)return b.CustomName;int e=cd.IndexOf('\n',p);return cd.Substring(p+key.Length+1,(e<0?cd.Length:e)-p-key.Length-1).Trim();}
void DrawFuel(){int si=NextSurface(_sfFuel,"fuel");if(si<0)return;var sf=_sfFuel[si];SetupSurf(sf);Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y;var ht=new List<int>();var ot=new List<int>();var gs=new List<int>();var vs=new List<int>();var leaks=new List<string>();double hv=0,ov=0,vr=0;int hc=0,oc=0;foreach(var x in _pTank){bool hy=x.BlockDefinition.SubtypeId.IndexOf("Hydrogen",StringComparison.OrdinalIgnoreCase)>=0;int state=BState(x,x.FilledRatio<.01);if(hy){ht.Add(state);hv+=x.FilledRatio;hc++;}else{ot.Add(state);ov+=x.FilledRatio;oc++;}}var ice=MyItemType.MakeOre("Ice");double ia=0;foreach(var x in _pGen){double a=(double)x.GetInventory(0).GetItemAmount(ice);ia+=a;gs.Add(BState(x,a<=pIceCrit));}foreach(var x in _pVent){if(x.Depressurize)continue;int st=!x.IsFunctional||!x.CanPressurize?2:!x.Enabled||x.GetOxygenLevel()<.95f?1:0;vs.Add(st);if(st==0)vr++;else leaks.Add(x.CustomName);}using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);CR(f,v+new Vector2(w*.5f,23),new Vector2(w,46),CLR_PANEL);CT(f,"FUEL & LIFE SUPPORT",v+new Vector2(w*.5f,7),new Color(80,200,255),.68f,TextAlignment.CENTER);float y=60;if(ht.Count>0)y+=PowerDots(f,"HYDROGEN TANKS",ht,v,w,y)+5;if(ot.Count>0)y+=PowerDots(f,"OXYGEN TANKS",ot,v,w,y)+5;CR(f,v+new Vector2(w*.5f,y),new Vector2(w*.9f,2),CLR_ACCENT);y+=14;if(hc>0){PowerBar(f,"HYDROGEN LEVEL",hv,hc,v,w,y,new Color(80,200,255),"");y+=58;}if(oc>0){PowerBar(f,"OXYGEN LEVEL",ov,oc,v,w,y,CLR_OK,"");y+=58;}if(vs.Count>0){PowerBar(f,"ROOM VENTS SEALED",vr,vs.Count,v,w,y,leaks.Count>0?CLR_WARN:CLR_OK,"");y+=58;if(leaks.Count>0){CT(f,"LEAK / LOW PRESSURE:",v+new Vector2(w*.05f,y),CLR_WARN,.34f,TextAlignment.LEFT);string s="";for(int i=0;i<leaks.Count&&i<3;i++)s+=(i>0?", ":"")+Cut(leaks[i],22);CT(f,s,v+new Vector2(w*.05f,y+26),CLR_ERR,.30f,TextAlignment.LEFT);y+=54;}}else{CT(f,"ROOM VENTS",v+new Vector2(w*.05f,y),CLR_DIM,.36f,TextAlignment.LEFT);CT(f,"No pressurizing [AGM-Vent] vents",v+new Vector2(w*.05f,y+28),CLR_DIM,.28f,TextAlignment.LEFT);y+=58;}if(gs.Count>0&&y<h-72)PowerBar(f,"GENERATOR ICE",ia,pIceWarn*gs.Count,v,w,y,CLR_WARN,"kg");CR(f,v+new Vector2(w*.5f,h-13),new Vector2(w,26),CLR_PANEL);CT(f,"TAGGED VENTS ONLY - DEPRESSURIZE VENTS IGNORED",v+new Vector2(w*.5f,h-22),CLR_DIM,.30f,TextAlignment.CENTER);}}
void DrawDock(){int si=NextSurface(_sfDock,"dock");if(si<0)return;var sf=_sfDock[si];SetupSurf(sf);int rows=5,pages=Math.Max(1,(int)Math.Ceiling(_pDock.Count/(double)rows)),pg=GetLcdPage(sf);if(pg>=pages){pg=0;SetLcdPage(sf,0);}Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y,rh=(h-70)/rows;using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);CR(f,v+new Vector2(w*.5f,18),new Vector2(w,36),CLR_PANEL);CT(f,"DOCK MONITOR",v+new Vector2(w*.5f,6),CLR_ACCENT,.58f,TextAlignment.CENTER);if(pages>1)CT(f,"P"+(pg+1)+"/"+pages,v+new Vector2(w*.96f,8),CLR_ACCENT,.30f,TextAlignment.RIGHT);for(int j=0;j<rows;j++){int di=pg*rows+j;if(di>=_pDock.Count)break;var d=_pDock[di];float y=43+j*rh,cardH=rh-6;bool linked=d.Status==MyShipConnectorStatus.Connected&&d.OtherConnector!=null;CR(f,v+new Vector2(w*.5f,y+cardH*.5f),new Vector2(w*.94f,cardH),CLR_PANEL);Color sc=linked?CLR_OK:CLR_WARN;CT(f,BName(d,"dock"),v+new Vector2(w*.04f,y+4),CLR_WHITE,.30f,TextAlignment.LEFT);CT(f,linked?"OCCUPIED":"EMPTY",v+new Vector2(w*.96f,y+4),sc,.28f,TextAlignment.RIGHT);if(!linked){CT(f,"Slot clear - no connected ship",v+new Vector2(w*.05f,y+cardH*.55f),CLR_DIM,.24f,TextAlignment.LEFT);continue;}var bs=new List<IMyTerminalBlock>();GridTerminalSystem.GetBlocksOfType<IMyTerminalBlock>(bs,b=>b.CubeGrid.IsSameConstructAs(d.OtherConnector.CubeGrid));double bc=0,bm=0,h2=0,o2=0,cv=0,cm=0;int bats=0,hc=0,oc=0,inv=0;foreach(var block in bs){var bat=block as IMyBatteryBlock;if(bat!=null){bc+=bat.CurrentStoredPower;bm+=bat.MaxStoredPower;bats++;}var tank=block as IMyGasTank;if(tank!=null){if(tank.BlockDefinition.SubtypeId.IndexOf("Hydrogen",StringComparison.OrdinalIgnoreCase)>=0){h2+=tank.FilledRatio;hc++;}else{o2+=tank.FilledRatio;oc++;}}for(int k=0;k<block.InventoryCount;k++){cv+=(double)block.GetInventory(k).CurrentVolume;cm+=(double)block.GetInventory(k).MaxVolume;inv++;}}double pp=bm>0?bc/bm*100:0,hp=hc>0?h2/hc*100:0,op=oc>0?o2/oc*100:0,cp=cm>0?cv/cm*100:0;string ship=d.OtherConnector.CubeGrid.CustomName;CT(f,"Ship: "+(ship.Length>0?ship:d.OtherConnector.CustomName),v+new Vector2(w*.05f,y+cardH*.32f),CLR_DIM,.22f,TextAlignment.LEFT);CT(f,"Bats "+bats+"  H2 "+hc+"  O2 "+oc+"  Inv "+inv,v+new Vector2(w*.05f,y+cardH*.63f),CLR_DIM,.22f,TextAlignment.LEFT);DockBar(f,v+new Vector2(w*.45f,y+cardH*.30f),w*.22f,"PWR",pp,CLR_OK);DockBar(f,v+new Vector2(w*.72f,y+cardH*.30f),w*.22f,"H2",hp,CLR_CYAN);DockBar(f,v+new Vector2(w*.45f,y+cardH*.66f),w*.22f,"O2",op,new Color(120,220,255));DockBar(f,v+new Vector2(w*.72f,y+cardH*.66f),w*.22f,"CAR",cp,cp>90?CLR_ERR:cp>70?CLR_WARN:CLR_ACCENT);}if(_pDock.Count==0)CT(f,"No tagged [AGM-Dock] connectors",v+z*.5f,CLR_DIM,.42f,TextAlignment.CENTER);CR(f,v+new Vector2(w*.5f,h-12),new Vector2(w,24),CLR_PANEL);CT(f,"5 docks/page - PWR H2 O2 CARGO",v+new Vector2(w*.5f,h-20),CLR_DIM,.24f,TextAlignment.CENTER);}}
void DockBar(MySpriteDrawFrame f,Vector2 p,float w,string lab,double pct,Color c){CT(f,lab+" "+pct.ToString("F0")+"%",p,c,.21f,TextAlignment.LEFT);DrawBar(f,p+new Vector2(0,16),w,7,pct,100,c);}
void DrawDef(){int si=NextSurface(_sfDef,"defence");if(si<0)return;var sf=_sfDef[si];SetupSurf(sf);Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y;var ts=new List<int>();double ammo=0,ready=0;foreach(var x in _pTurret){double a=0;if(x.HasInventory){_itmScr.Clear();x.GetInventory(0).GetItems(_itmScr);foreach(var ammoItem in _itmScr)a+=(double)ammoItem.Amount;}ammo+=a;int turretState=!x.IsFunctional?2:!x.Enabled||a<=0?1:0;ts.Add(turretState);if(turretState==0)ready++;}using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);CR(f,v+new Vector2(w*.5f,20),new Vector2(w,40),CLR_PANEL);CT(f,_safeMode?"DEFENCE - SAFE MODE":"DEFENCE - COMBAT",v+new Vector2(w*.5f,7),_safeMode?CLR_WARN:CLR_OK,.62f,TextAlignment.CENTER);float y=58;y+=PowerDots(f,"TAGGED TURRETS",ts,v,w,y)+12;PowerBar(f,"TURRETS READY",ready,Math.Max(ts.Count,1),v,w,y,CLR_OK,"");y+=70;PowerBar(f,"LOADED AMMO",ammo,Math.Max(ts.Count*20,1),v,w,y,CLR_ACCENT,"rounds");y+=75;CT(f,_safeMode?"SAFE MODE - TAGGED TURRETS DISABLED":"COMBAT MODE - TAGGED TURRETS ENABLED",v+new Vector2(w*.5f,y),_safeMode?CLR_WARN:CLR_OK,.38f,TextAlignment.CENTER);CR(f,v+new Vector2(w*.5f,h-13),new Vector2(w,26),CLR_PANEL);CT(f,"GREEN READY   AMBER ATTENTION   RED DAMAGED",v+new Vector2(w*.5f,h-22),CLR_DIM,.27f,TextAlignment.CENTER);}}
void DrawProd(){int si=NextSurface(_sfProd,"production");if(si<0)return;var sf=_sfProd[si];SetupSurf(sf);Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y;var aa=new List<int>();var rr=new List<int>();double aw=0,rw=0,aq=0,ri=0,rim=0;foreach(var x in _pAsm){int state=!x.IsFunctional?2:!x.Enabled||!x.IsProducing?1:0;aa.Add(state);if(x.IsProducing)aw++;_queScr.Clear();x.GetQueue(_queScr);foreach(var queueItem in _queScr)aq+=(double)queueItem.Amount;}foreach(var x in _pRef){int state=!x.IsFunctional?2:!x.Enabled||!x.IsProducing?1:0;rr.Add(state);if(x.IsProducing)rw++;ri+=(double)x.GetInventory(0).CurrentVolume;rim+=(double)x.GetInventory(0).MaxVolume;}using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);CR(f,v+new Vector2(w*.5f,23),new Vector2(w,46),CLR_PANEL);CT(f,"PRODUCTION",v+new Vector2(w*.5f,7),new Color(180,120,255),.70f,TextAlignment.CENTER);float y=62;if(aa.Count>0)y+=StateDots(f,"ASSEMBLERS - QUEUE "+Fmt(aq),aa,v,w,y,"WORKING")+6;if(rr.Count>0)y+=StateDots(f,"REFINERIES",rr,v,w,y,"WORKING")+6;CR(f,v+new Vector2(w*.5f,y),new Vector2(w*.9f,2),CLR_ACCENT);y+=14;if(aa.Count>0){PowerBar(f,"ASSEMBLERS WORKING",aw,aa.Count,v,w,y,CLR_OK,"");y+=60;}if(rr.Count>0){PowerBar(f,"REFINERIES WORKING",rw,rr.Count,v,w,y,CLR_OK,"");y+=60;PowerBar(f,"REFINERY INPUT",ri,Math.Max(rim,1),v,w,y,CLR_ACCENT,"m3");}CR(f,v+new Vector2(w*.5f,h-13),new Vector2(w,26),CLR_PANEL);CT(f,"GREEN WORKING   AMBER IDLE   RED DAMAGED",v+new Vector2(w*.5f,h-22),CLR_DIM,.30f,TextAlignment.CENTER);}}
double CatFill(List<IMyTerminalBlock>x){double a=0,m=0;foreach(var b in x){a+=(double)b.GetInventory(0).CurrentVolume;m+=(double)b.GetInventory(0).MaxVolume;}return m>0?a/m*100:0;}
string Cut(string s,int n){return s.Length<=n?s:s.Substring(0,Math.Max(0,n-3))+"...";}
void LogBar(MySpriteDrawFrame f,Vector2 p,float w,string name,double pct,Color c){double pc=Math.Max(0,Math.Min(100,pct));CT(f,name,p,CLR_WHITE,.34f,TextAlignment.LEFT);CT(f,pc.ToString("F0")+"%",p+new Vector2(w,0),pc>=90?CLR_ERR:pc>=65?CLR_WARN:c,.34f,TextAlignment.RIGHT);DrawBar(f,p+new Vector2(0,22),w,14,pc,100,pc>=90?CLR_ERR:pc>=65?CLR_WARN:c);}
void DrawLog(){int si=NextSurface(_sfLog,"logistics");if(si<0)return;var sf=_sfLog[si];SetupSurf(sf);Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y;double autoWork=_sortersOn?1:0;using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);CR(f,v+new Vector2(w*.5f,23),new Vector2(w,46),CLR_PANEL);CT(f,"LOGISTICS",v+new Vector2(w*.5f,7),new Color(100,220,180),.70f,TextAlignment.CENTER);float y=62;CT(f,"AGM INVENTORY SORTER",v+new Vector2(w*.05f,y),CLR_WHITE,.42f,TextAlignment.LEFT);CT(f,_sortersOn?"ONLINE":"OFFLINE",v+new Vector2(w*.95f,y),_sortersOn?CLR_OK:CLR_WARN,.42f,TextAlignment.RIGHT);y+=34;DrawBar(f,v+new Vector2(w*.05f,y),w*.90f,18,autoWork,1,_sortersOn?CLR_OK:CLR_WARN);y+=38;CT(f,"SCRIPT MOVES ITEMS BETWEEN TAGGED CARGOS",v+new Vector2(w*.05f,y),CLR_DIM,.34f,TextAlignment.LEFT);y+=32;CR(f,v+new Vector2(w*.5f,y),new Vector2(w*.9f,2),CLR_ACCENT);y+=22;float cw=w*.27f,g=w*.045f,x0=w*.05f;LogBar(f,v+new Vector2(x0,y),cw,"ORE",CatFill(_oreC),CLR_ACCENT);LogBar(f,v+new Vector2(x0+cw+g,y),cw,"INGOT",CatFill(_ingC),CLR_OK);LogBar(f,v+new Vector2(x0+(cw+g)*2,y),cw,"COMPONENT",CatFill(_cmpC),new Color(120,200,255));y+=58;LogBar(f,v+new Vector2(x0,y),cw,"AMMO",CatFill(_ammoC),CLR_WARN);LogBar(f,v+new Vector2(x0+cw+g,y),cw,"TOOLS",CatFill(_toolC),new Color(180,120,255));LogBar(f,v+new Vector2(x0+(cw+g)*2,y),cw,"BOTTLES",CatFill(_botC),new Color(80,200,255));y+=58;LogBar(f,v+new Vector2(x0,y),cw,"FOOD",CatFill(_foodC),new Color(255,180,120));LogBar(f,v+new Vector2(x0+cw+g,y),cw,"SEEDS",CatFill(_seedC),new Color(130,255,130));LogBar(f,v+new Vector2(x0+(cw+g)*2,y),cw,"INGREDIENT",CatFill(_ingIC),new Color(255,160,255));y+=60;CR(f,v+new Vector2(w*.5f,y),new Vector2(w*.9f,2),CLR_ACCENT);y+=18;CT(f,"RECENT AGM TRANSFERS",v+new Vector2(w*.05f,y),CLR_WHITE,.38f,TextAlignment.LEFT);y+=28;int st=Math.Max(0,_log.Count-3);for(int i=st;i<_log.Count&&y<h-38;i++){CT(f,Cut(_log[i],82),v+new Vector2(w*.05f,y),CLR_DIM,.30f,TextAlignment.LEFT);y+=24;}CR(f,v+new Vector2(w*.5f,h-13),new Vector2(w,26),CLR_PANEL);CT(f,"ONE PAGE LIVE CARGO + SCRIPT SORTING STATUS",v+new Vector2(w*.5f,h-22),CLR_DIM,.30f,TextAlignment.CENTER);}}
void DrawAlert(){foreach(var sf in _sfAlert){SetupSurf(sf);var tb=sf as IMyTerminalBlock;string role=tb!=null?AlertRoleName(tb):"";string title="",stat="",detail="";double pct=0;Color c;float blink;AlertData(role,out title,out stat,out detail,out pct,out c,out blink);Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y;bool thin=h<150||w>h*3.2f;using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);if(thin){CR(f,v+new Vector2(w*.5f,h*.10f),new Vector2(w,Math.Max(4,h*.12f)),c);float ts=Math.Max(.14f,Math.Min(.26f,h/190f));float ss=Math.Max(.18f,Math.Min(.34f,h/135f));CT(f,title,v+new Vector2(w*.04f,h*.32f),c,ts,TextAlignment.LEFT);CT(f,stat,v+new Vector2(w*.50f,h*.28f),c,ss,TextAlignment.CENTER);DrawBar(f,v+new Vector2(w*.18f,h*.58f),w*.64f,Math.Max(5,h*.10f),pct,100,c);CT(f,detail,v+new Vector2(w*.96f,h*.60f),CLR_WHITE,ts,TextAlignment.RIGHT);continue;}CR(f,v+new Vector2(w*.5f,10),new Vector2(w,20),c);CR(f,v+new Vector2(w*.5f,h*.24f),new Vector2(w*.90f,h*.28f),CLR_PANEL);CT(f,title,v+new Vector2(w*.5f,h*.08f),c,.42f,TextAlignment.CENTER);CT(f,stat,v+new Vector2(w*.5f,h*.18f),c,.72f,TextAlignment.CENTER);if(role.Length>0){DrawBar(f,v+new Vector2(w*.14f,h*.43f),w*.72f,h*.10f,pct,100,c);CT(f,detail,v+new Vector2(w*.5f,h*.58f),CLR_WHITE,.34f,TextAlignment.CENTER);}else CT(f,detail,v+new Vector2(w*.5f,h*.48f),CLR_WHITE,.28f,TextAlignment.CENTER);CT(f,blink>0?"BLINK":"STEADY",v+new Vector2(w*.5f,h*.78f),CLR_DIM,.24f,TextAlignment.CENTER);}}}
void CFrame(IMyTextSurface sf,string title,int pg,int pages,Color col,List<string>n,List<MyDefinitionId>ids,List<double>vals,List<double>maxs,string footer){SetupSurf(sf);Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y,rh=28,y=42;using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);int rows=Math.Min(n.Count,14),start=pg*14;for(int j=0;j<rows&&start+j<n.Count;j++){int i=start+j;float cy=v.Y+y+j*rh;try{f.Add(new MySprite(SpriteType.TEXTURE,ids[i].ToString(),new Vector2(v.X+w*.035f,cy+7),new Vector2(22,22),Color.White));}catch{}CT(f,CN(n[i]),new Vector2(v.X+w*.08f,cy),CLR_WHITE,.3f,TextAlignment.LEFT);double q=maxs[i]>0?maxs[i]:Math.Max(vals[i],1);float r=(float)Math.Min(vals[i]/q,1);CR(f,new Vector2(v.X+w*.69f,cy+7),new Vector2(w*.34f,10),CLR_BAR_BG);if(r>0)CR(f,new Vector2(v.X+w*.52f+w*.34f*r*.5f,cy+7),new Vector2(w*.34f*r,10),col);CT(f,Fmt(vals[i]),new Vector2(v.X+w*.97f,cy),CLR_WHITE,.3f,TextAlignment.RIGHT);}CR(f,v+new Vector2(w*.5f,18),new Vector2(w,36),CLR_PANEL);CT(f,title,v+new Vector2(w*.5f,7),CLR_ACCENT,.52f,TextAlignment.CENTER);if(pages>1)CT(f,"P"+(pg+1)+"/"+pages,v+new Vector2(w*.97f,7),CLR_ACCENT,.28f,TextAlignment.RIGHT);CR(f,v+new Vector2(w*.5f,h-11),new Vector2(w,22),CLR_PANEL);CT(f,footer,v+new Vector2(w*.5f,h-18),CLR_DIM,.25f,TextAlignment.CENTER);}}
void CDrawInv(List<IMyTextSurface>ss,string title,string[]names,string tid,Color col,List<IMyTerminalBlock>boxes){int si=NextSurface(ss,title);if(si<0)return;var n=new List<string>();var ids=new List<MyDefinitionId>();var vals=new List<double>();var qs=new List<double>();foreach(var x in names){var id=ResolveDisplayId(x,tid);double a=0;_gAmt.TryGetValue(id,out a);double q=DisplayQuota(id);if(a<=0&&q<=0)continue;n.Add(x);ids.Add(id);vals.Add(a);qs.Add(q);}int pages=Math.Max(1,(int)Math.Ceiling(n.Count/14.0)),pg=GetLcdPage(ss[si]);if(pg>=pages){pg=0;SetLcdPage(ss[si],0);}double vol=0,cap=0;foreach(var b in boxes){vol+=(double)b.GetInventory(0).CurrentVolume*1000;cap+=(double)b.GetInventory(0).MaxVolume*1000;}CFrame(ss[si],title,pg,pages,col,n,ids,vals,qs,Fmt(vol)+" / "+Fmt(cap)+" L");}
void CDrawKnown(List<IMyTextSurface>ss,string title,string tid,Color col,List<IMyTerminalBlock>boxes,int mode){var n=new List<string>();foreach(var k in _known){string s=k.SubtypeId.ToString(),t=k.TypeId.ToString();bool ok=mode==0?t.Contains(tid):mode==1?t.Contains(T_CON)&&IsFoodSub(s):mode==2?t.Contains(T_GAS)||t.Contains(T_OXY):(t.Contains(T_CON)||t.Contains(T_PHYS))&&IsIngredientSub(s);if(ok&&!n.Contains(s))n.Add(s);}n.Sort();CDrawInv(ss,title,n.ToArray(),tid,col,boxes);}
int GetLcdPage(IMyTextSurface sf){var p=sf as IMyTextPanel;if(p==null)return 0;string cd=p.CustomData;if(string.IsNullOrEmpty(cd))return 0;int idx=cd.IndexOf("page=");if(idx<0)return 0;int end=cd.IndexOf('\n',idx);string val=end>=0?cd.Substring(idx+5,end-idx-5).Trim():cd.Substring(idx+5).Trim();int v;if(!int.TryParse(val,out v)||v<0)return 0;return v;}
void SetLcdPage(IMyTextSurface sf,int pg){var p=sf as IMyTextPanel;if(p==null)return;string cd=p.CustomData;int idx=cd.IndexOf("page=");string repl="page="+pg;if(idx>=0){int end=cd.IndexOf('\n',idx);cd=end>=0?cd.Substring(0,idx)+repl+cd.Substring(end):cd.Substring(0,idx)+repl;}else{cd=repl+"\n"+cd;}p.CustomData=cd;}
void BindLcds(){_sfMain.Clear();_sfOre.Clear();_sfIngot.Clear();_sfComp.Clear();_sfAmmo.Clear();_sfTools.Clear();_sfAction.Clear();_sfPerf.Clear();_sfFood.Clear();_sfBot.Clear();_sfSeed.Clear();_sfIngI.Clear();_sfPower.Clear();_sfFuel.Clear();_sfDock.Clear();_sfDef.Clear();_sfProd.Clear();_sfAlert.Clear();_sfLog.Clear();var pans=new List<IMyTextPanel>();GridTerminalSystem.GetBlocksOfType<IMyTextPanel>(pans,p=>(HasNameTag(p,AGM_TAG)||HasTag(p,P_ALERT))&&!IsExcluded(p));foreach(var p in pans){SetupSurf(p);if(!p.CustomData.Contains("page="))p.CustomData="page=0\n"+p.CustomData;if(HasTag(p,P_ALERT))_sfAlert.Add(p);else if(LcdRole(p,"Power"))_sfPower.Add(p);else if(LcdRole(p,"Fuel"))_sfFuel.Add(p);else if(LcdRole(p,"Dock"))_sfDock.Add(p);else if(LcdRole(p,"Defence")||LcdRole(p,"Defense"))_sfDef.Add(p);else if(LcdRole(p,"Production"))_sfProd.Add(p);else if(LcdRole(p,"Logistics"))_sfLog.Add(p);else if(LcdRole(p,"Main"))_sfMain.Add(p);else if(LcdRole(p,"Autocraft")||LcdRole(p,"Crafting")){p.ContentType=ContentType.TEXT_AND_IMAGE;p.WriteText("");continue;}else if(LcdRole(p,"OreStock")||LcdRole(p,"Ore"))_sfOre.Add(p);else if(LcdRole(p,"IngotStock")||LcdRole(p,"Ingot"))_sfIngot.Add(p);else if(LcdRole(p,"ComponentStock")||LcdRole(p,"Component"))_sfComp.Add(p);else if(LcdRole(p,"AmmoStock")||LcdRole(p,"Ammo"))_sfAmmo.Add(p);else if(LcdRole(p,"ToolStock")||LcdRole(p,"Tools"))_sfTools.Add(p);else if(LcdRole(p,"FoodStock")||LcdRole(p,"Food"))_sfFood.Add(p);else if(LcdRole(p,"BottleStock")||LcdRole(p,"Bottles"))_sfBot.Add(p);else if(LcdRole(p,"SeedStock")||LcdRole(p,"Seeds"))_sfSeed.Add(p);else if(LcdRole(p,"IngredientStock")||LcdRole(p,"Ingredients"))_sfIngI.Add(p);else _sfMain.Add(p);}}
bool InList(string name,string[]list){foreach(var n in list)if(n.Equals(name,StringComparison.OrdinalIgnoreCase))return true;return false;}
bool IsIngredientSub(string name){return InList(name,ING_SUBS)||InList(name,PHYS_ING);}
bool IsFoodSub(string name){return InList(name,FOOD_SUBS)||name.StartsWith("MealPack_",StringComparison.OrdinalIgnoreCase);}
string ShortType(MyDefinitionId id){string t=id.TypeId.ToString();int i=t.LastIndexOf('_');return i>=0?t.Substring(i+1):t;}
double DisplayQuota(MyDefinitionId id){double q;if(_displayQuota.TryGetValue(ShortType(id)+"/"+id.SubtypeId.ToString(),out q))return q;if(_displayQuota.TryGetValue(id.SubtypeId.ToString(),out q))return q;return 0;}
int NextSurface(List<IMyTextSurface>surfs,string key){if(surfs.Count==0)return-1;int i=0;_drawCursor.TryGetValue(key,out i);if(i<0||i>=surfs.Count)i=0;_drawCursor[key]=(i+1)%surfs.Count;return i;}
MyDefinitionId ResolveDisplayId(string name,string preferred){MyDefinitionId id=default(MyDefinitionId);string pt=preferred;if(preferred==T_CON&&InList(name,PHYS_ING))pt=T_PHYS;MyDefinitionId.TryParse(OB+pt+"/"+name,out id);if(_gAmt.ContainsKey(id)||DisplayQuota(id)>0)return id;if(preferred==T_GAS){MyDefinitionId.TryParse(OB+T_OXY+"/"+name,out id);if(_gAmt.ContainsKey(id)||DisplayQuota(id)>0)return id;}foreach(var k in _known)if(k.SubtypeId.ToString()==name&&(k.TypeId.ToString().Contains(pt)||(preferred==T_GAS&&k.TypeId.ToString().Contains(T_OXY))))return k;return id;}
void DrawBoot(float p,string msg){var pb=Me as IMyTextSurfaceProvider;if(pb==null||pb.SurfaceCount==0)return;DrawBootSurface(pb.GetSurface(0),p,msg);}
void DrawBootAll(float p,string msg){DrawBoot(p,msg);DrawBootList(_sfMain,p,msg);DrawBootList(_sfOre,p,msg);DrawBootList(_sfIngot,p,msg);DrawBootList(_sfComp,p,msg);DrawBootList(_sfAmmo,p,msg);DrawBootList(_sfTools,p,msg);DrawBootList(_sfFood,p,msg);DrawBootList(_sfBot,p,msg);DrawBootList(_sfSeed,p,msg);DrawBootList(_sfIngI,p,msg);DrawBootList(_sfPower,p,msg);DrawBootList(_sfFuel,p,msg);DrawBootList(_sfDock,p,msg);DrawBootList(_sfDef,p,msg);DrawBootList(_sfProd,p,msg);DrawBootList(_sfAlert,p,msg);DrawBootList(_sfLog,p,msg);}
void DrawBootList(List<IMyTextSurface>ss,float p,string msg){foreach(var sf in ss)DrawBootSurface(sf,p,msg);}
void DrawBootSurface(IMyTextSurface sf,float p,string msg){SetupSurf(sf);Vector2 vp=(sf.TextureSize-sf.SurfaceSize)*0.5f,sz=sf.SurfaceSize;float w=sz.X,h=sz.Y,cx=vp.X+w*.5f,cy=vp.Y+h*.5f;float sc=Math.Max(.45f,Math.Min(.95f,h/420f));using(var f=sf.DrawFrame()){CR(f,vp+sz*.5f,sz,CLR_BG);CR(f,vp+new Vector2(w*.5f,Math.Max(3,h*.018f)),new Vector2(w,Math.Max(5,h*.025f)),CLR_ACCENT);CT(f,"AGM",new Vector2(cx,cy-h*.22f),CLR_ACCENT,sc*1.25f,TextAlignment.CENTER);CT(f,"AUTOGRID MANAGER",new Vector2(cx,cy-h*.10f),CLR_WHITE,sc*.48f,TextAlignment.CENTER);CT(f,msg,new Vector2(cx,cy+h*.02f),CLR_DIM,sc*.40f,TextAlignment.CENTER);float bw=w*.76f,bh=Math.Max(8,h*.045f),bx=vp.X+(w-bw)*.5f,by=cy+h*.11f;CR(f,new Vector2(bx+bw*.5f,by+bh*.5f),new Vector2(bw,bh),CLR_BAR_BG);float fw=bw*MathHelper.Clamp(p,0f,1f);if(fw>1)CR(f,new Vector2(bx+fw*.5f,by+bh*.5f),new Vector2(fw,bh),CLR_ACCENT);CT(f,((int)(p*100))+"%",new Vector2(cx,by+bh+h*.035f),CLR_ACCENT,sc*.38f,TextAlignment.CENTER);CR(f,vp+new Vector2(w*.5f,h-Math.Max(3,h*.018f)),new Vector2(w,Math.Max(5,h*.025f)),CLR_ACCENT);}}
void WriteStockTmpl(IMyTerminalBlock b){if(b.CustomData.Contains(STOCK_START)||!string.IsNullOrWhiteSpace(b.CustomData))return;var sb=new StringBuilder();sb.Append(STOCK_START);sb.Append("\n");sb.Append("~ amount=exact, amountM=minimum, amountL=limit, amountP=pinned, all=fill\n");sb.Append("~ Use Type/Subtype for ambiguous or modded items\n");foreach(var n in INGOT_NAMES)sb.Append("Ingot/"+n+"=0\n");foreach(var c in COMP_NAMES)sb.Append(c+"=0\n");foreach(var ammo in AMMO_NAMES)sb.Append(ammo+"=0\n");sb.Append("WelderItem=0\nAngleGrinderItem=0\nHandDrillItem=0\n");sb.Append(STOCK_END);sb.Append("\n");b.CustomData=sb.ToString();}
bool IsOnExcludedGrid(IMyTerminalBlock b){return _excl.Contains(b.CubeGrid);}
